/**
 * Multi-Label Selection Stage
 *
 * Implements sophisticated multi-label selection logic based on ranking algorithms,
 * confidence thresholds, co-presence rules, and AI routing decisions.
 *
 * This stage is responsible for:
 * - Ranking categories by final scores
 * - Selecting primary and secondary labels based on confidence and gap thresholds
 * - Enforcing co-presence rules and allowed combinations
 * - Determining AI classification requirements
 * - Generating complete selection rationale and audit trails
 */

import {
  CategoryScore,
  MultiLabelConfig,
  ConfidenceThresholds,
  SelectedLabel,
  SelectionSummary,
  MultiLabelSelectionResult,
} from './types';
import { ClassificationSession } from '../types/classification-session';
import { ClassificationResult } from '../types/classification-result';
import { EmailMessage } from '../types/email-message';

/**
 * Execute multi-label selection stage (canonical signature)
 *
 * Ranks categories, selects primary/secondary labels, and determines AI routing needs.
 *
 * Mutates the result object in place by setting primaryCategory, secondaryCategories,
 * and updating explainability trace with selection decisions.
 */
// FIXME some parameters appear unused - should these just be documented as common interface parameters?
export function executeMultiLabelSelection(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: MultiLabelConfig,
  thresholds: ConfidenceThresholds
): void {
  const startTime = Date.now();

  // Validate configuration
  validateConfiguration(config, thresholds);

  // Extract candidate scores from result.scoreBreakdown
  const candidateScores: Record<string, CategoryScore> = {};
  for (const [category, scoreData] of Object.entries(result.scoreBreakdown.categoryScores)) {
    candidateScores[category] = {
      score: scoreData.finalScore || scoreData.baseScore || 0,
      confidence: scoreData.finalScore || scoreData.baseScore || 0,
      rationale: '',
      decision: undefined,
    };
  }

  // Rank categories by score
  const rankedCategories = rankCategoriesByScore(candidateScores);

  if (rankedCategories.length === 0) {
    const duration = Date.now() - startTime;
    result.processingDurationMs += duration;
    result.explainabilityTrace.stageTimings['multi_label_selection'] = duration;
    result.explainabilityTrace.configurationRefs['multi_label_selection'] = 'settings.multi_label_selection';
    result.explainabilityTrace.multiLabelSelection = [];
    return;
  }

  const selectedLabels: SelectedLabel[] = [];

  // Select primary label
  const primaryCandidate = rankedCategories[0];
  if (primaryCandidate.score >= thresholds.lowConfidence) {
    const primaryLabel: SelectedLabel = {
      category: primaryCandidate.category,
      subtype: primaryCandidate.selectedSubtypeId || null,
      confidence: primaryCandidate.confidence,
      score: primaryCandidate.score,
      isPrimary: true,
      labelOrder: 1,
      selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${thresholds.lowConfidence})`,
    };
    selectedLabels.push(primaryLabel);

    // Select secondary labels
    selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate, config, thresholds);
  }

  // Update category decisions
  updateCategoryDecisions(candidateScores, selectedLabels, thresholds);

  // Determine AI classification need
  const needsAiClassification = determineAiClassificationNeed(selectedLabels, thresholds);

  const duration = Date.now() - startTime;

  // Mutate result: Update primary and secondary categories
  if (selectedLabels.length > 0) {
    const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];
    result.primaryCategory = primaryLabel.category;
    result.secondaryCategories = selectedLabels.filter((l) => !l.isPrimary).map((l) => l.category);
    result.confidence = primaryLabel.confidence / 100; // Normalize to 0-1
  }

  // Update AI routing flag
  result.aiRoutingUsed = needsAiClassification;

  // Update result processing duration
  result.processingDurationMs += duration;

  // Add parallel stage result tracking
  result.parallelStageResults.push({
    stageId: `multi_label_selection_${result.id}`,
    stageName: 'multi_label_selection',
    executionTimeMs: duration,
    parallelWithStages: [],
    dependentOnStages: ['disambiguation'],
    cacheHitsCount: 0,
    errorCount: 0,
  });

  // Update explainability trace (convert to ExplainabilityTrace.MultiLabelResult format)
  const multiLabelResults: Array<{
    selectedCategories: string[];
    rejectedCategories: Array<{
      category: string;
      score: number;
      rejectionReason: string;
    }>;
    coPresenceRulesApplied: string[];
    maxLabelsLimit: number;
    minSecondaryConfidence: number;
    reason: string;
  }> = [
    {
      selectedCategories: selectedLabels.map((l) => l.category),
      rejectedCategories: rankedCategories
        .filter((cat) => !selectedLabels.some((l) => l.category === cat.category))
        .map((cat) => ({
          category: cat.category,
          score: cat.score,
          rejectionReason:
            cat.score < thresholds.lowConfidence
              ? `Below minimum threshold (${cat.score} < ${thresholds.lowConfidence})`
              : 'Exceeded max labels limit or failed combination rules',
        })),
      coPresenceRulesApplied: [], // Populated based on allowed combinations
      maxLabelsLimit: config.maxLabels,
      minSecondaryConfidence: config.minSecondaryConfidence,
      reason:
        selectedLabels.length > 0
          ? `Selected ${selectedLabels.length} labels with primary: ${selectedLabels.find((l) => l.isPrimary)?.category || selectedLabels[0].category}`
          : 'No labels met minimum confidence threshold',
    },
  ];

  result.explainabilityTrace.multiLabelSelection = multiLabelResults;
  result.explainabilityTrace.stageTimings['multi_label_selection'] = duration;
  result.explainabilityTrace.configurationRefs['multi_label_selection'] = 'settings.multi_label_selection';
}

/**
 * Validate configuration parameters
 */
function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
  if (config.maxLabels < 0) {
    throw new Error('Invalid configuration: maxLabels cannot be negative');
  }

  if (config.minSecondaryConfidence < 0) {
    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
  }

  if (thresholds.highConfidence <= thresholds.mediumConfidence) {
    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
  }

  if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
  }

  if (thresholds.secondaryLabelMinGap < 0) {
    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
  }
}

/**
 * Rank categories by score in descending order, filtering out zero/negative scores
 */
function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
  category: string;
  score: number;
  confidence: number;
  rationale: string;
  selectedSubtypeId?: string | null;
}> {
  return Object.entries(candidateScores)
    .map(([category, scoreData]) => ({
      category,
      score: scoreData.score || 0,
      confidence: scoreData.confidence || 0,
      rationale: scoreData.rationale || '',
      selectedSubtypeId: scoreData.selectedSubtypeId,
    }))
    .filter((item) => item.score > 0)
    .sort((a, b) => {
      // Primary sort by score (descending)
      if (b.score !== a.score) {
        return b.score - a.score;
      }
      // Secondary sort by category name for stable ordering
      return a.category.localeCompare(b.category);
    });
}

/**
 * Select secondary labels within gap threshold and above minimum confidence
 */
function selectSecondaryLabels(
  rankedCategories: Array<{
    category: string;
    score: number;
    confidence: number;
    rationale: string;
    selectedSubtypeId?: string | null;
  }>,
  selectedLabels: SelectedLabel[],
  primaryCandidate: {
    category: string;
    score: number;
    confidence: number;
    rationale: string;
    selectedSubtypeId?: string | null;
  },
  config: MultiLabelConfig,
  thresholds: ConfidenceThresholds
): void {
  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
    return;
  }

  const primaryScore = primaryCandidate.score;

  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
    const candidate = rankedCategories[i];
    const scoreDifference = primaryScore - candidate.score;

    // Check if candidate meets secondary label criteria
    if (candidate.score >= config.minSecondaryConfidence && scoreDifference <= thresholds.secondaryLabelMinGap) {
      // Check if combination is allowed
      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
        const secondaryLabel: SelectedLabel = {
          category: candidate.category,
          subtype: candidate.selectedSubtypeId || null,
          confidence: candidate.confidence,
          score: candidate.score,
          isPrimary: false,
          labelOrder: selectedLabels.length + 1,
          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.minSecondaryConfidence})`,
        };
        selectedLabels.push(secondaryLabel);
      }
    }
  }
}

/**
 * Check if category combination is allowed based on configuration
 */
function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
  if (primaryCategory === candidateCategory) {
    return true;
  }

  // If strict mode is enabled and combinations are specified, only allow explicit combinations
  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
    const combination1 = `${primaryCategory}+${candidateCategory}`;
    const combination2 = `${candidateCategory}+${primaryCategory}`;
    return config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);
  }

  // If no combinations specified, allow all (default permissive mode)
  if (config.allowedCombinations.length === 0) {
    return true;
  }

  // If combinations are specified but not in strict mode, still check them
  const combination1 = `${primaryCategory}+${candidateCategory}`;
  const combination2 = `${candidateCategory}+${primaryCategory}`;
  const isExplicitlyAllowed =
    config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);

  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
  return isExplicitlyAllowed || !config.strictCombinationMode;
}

/**
 * Update category decisions based on selection results
 */
function updateCategoryDecisions(
  candidateScores: Record<string, CategoryScore>,
  selectedLabels: SelectedLabel[],
  thresholds: ConfidenceThresholds
): void {
  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));

  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
    const score = scoreData.score || 0;

    if (selectedCategoryNames.has(categoryCode)) {
      // Selected categories get decision based on confidence
      if (score >= thresholds.highConfidence) {
        scoreData.decision = 'positive';
        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidence}) - finalized without AI`;
      } else if (score >= thresholds.mediumConfidence) {
        scoreData.decision = 'candidate';
        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidence}) - may need AI validation`;
      } else {
        scoreData.decision = 'candidate';
        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidence}) - needs AI classification`;
      }
    } else {
      // Non-selected categories are rejected
      scoreData.decision = 'rejected';
      if (score < thresholds.lowConfidence) {
        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidence})`;
      } else {
        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
      }
    }
  }
}

/**
 * Determine if AI classification is needed based on selected labels
 */
function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
  if (selectedLabels.length === 0) {
    return true; // No labels selected - need AI
  }

  // Check if primary label has high confidence (can skip AI)
  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
  if (primaryLabel && primaryLabel.score >= thresholds.highConfidence) {
    return false; // High confidence primary - skip AI
  }

  // Check if any label is below medium confidence (needs AI)
  const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < thresholds.mediumConfidence);
  if (hasLowConfidenceLabel) {
    return true; // Has low confidence labels - need AI
  }

  // Conservative approach for medium confidence range
  return true;
}

/**
 * @deprecated Legacy class-based interface - use executeMultiLabelSelection function instead
 * NOTE: Kept for backward compatibility with existing unit tests (tests/unit/multi-label-selection.test.ts)
 * Will be removed once tests migrate to canonical signature pattern.
 */
export class MultiLabelSelectionStage {
  private config: MultiLabelConfig;
  private thresholds: ConfidenceThresholds;

  constructor(config: MultiLabelConfig, thresholds: ConfidenceThresholds) {
    this.validateConfiguration(config, thresholds);
    this.config = config;
    this.thresholds = thresholds;
  }

  /**
   * Validate configuration parameters
   */
  private validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
    if (config.maxLabels < 0) {
      throw new Error('Invalid configuration: maxLabels cannot be negative');
    }

    if (config.minSecondaryConfidence < 0) {
      throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
    }

    if (thresholds.highConfidence <= thresholds.mediumConfidence) {
      throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
    }

    if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
      throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
    }

    if (thresholds.secondaryLabelMinGap < 0) {
      throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
    }
  }

  /**
   * Rank categories by score in descending order, filtering out zero/negative scores
   */
  public rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
    category: string;
    score: number;
    confidence: number;
    rationale: string;
    selectedSubtypeId?: string | null;
  }> {
    return Object.entries(candidateScores)
      .map(([category, scoreData]) => ({
        category,
        score: scoreData.score || 0,
        confidence: scoreData.confidence || 0,
        rationale: scoreData.rationale || '',
        selectedSubtypeId: scoreData.selectedSubtypeId,
      }))
      .filter((item) => item.score > 0)
      .sort((a, b) => {
        // Primary sort by score (descending)
        if (b.score !== a.score) {
          return b.score - a.score;
        }
        // Secondary sort by category name for stable ordering
        return a.category.localeCompare(b.category);
      });
  }

  /**
   * Main selection logic: select labels based on multi-label selection rules
   */
  public selectLabels(candidateScores: Record<string, CategoryScore>): MultiLabelSelectionResult {
    const startTime = Date.now();

    // Rank categories by score
    const rankedCategories = this.rankCategoriesByScore(candidateScores);

    if (rankedCategories.length === 0) {
      return this.createNoSelectionResult(startTime, rankedCategories);
    }

    const selectedLabels: SelectedLabel[] = [];

    // Select primary label
    const primaryCandidate = rankedCategories[0];
    if (primaryCandidate.score >= this.thresholds.lowConfidence) {
      const primaryLabel: SelectedLabel = {
        category: primaryCandidate.category,
        subtype: primaryCandidate.selectedSubtypeId || null,
        confidence: primaryCandidate.confidence,
        score: primaryCandidate.score,
        isPrimary: true,
        labelOrder: 1,
        selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${this.thresholds.lowConfidence})`,
      };
      selectedLabels.push(primaryLabel);
    } else {
      return this.createNoSelectionResult(startTime, rankedCategories);
    }

    // Select secondary labels
    this.selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate);

    // Update category decisions
    this.updateCategoryDecisions(candidateScores, selectedLabels);

    // Determine AI classification need
    const needsAiClassification = this.determineAiClassificationNeed(selectedLabels);

    // Create selection summary
    const selectionSummary = this.createSelectionSummary(selectedLabels, rankedCategories, needsAiClassification);

    return {
      selectedLabels,
      needsAiClassification,
      selectionSummary,
      processingDurationMs: Date.now() - startTime,
    };
  }

  /**
   * Select secondary labels within gap threshold and above minimum confidence
   */
  private selectSecondaryLabels(
    rankedCategories: Array<{
      category: string;
      score: number;
      confidence: number;
      rationale: string;
      selectedSubtypeId?: string | null;
    }>,
    selectedLabels: SelectedLabel[],
    primaryCandidate: {
      category: string;
      score: number;
      confidence: number;
      rationale: string;
      selectedSubtypeId?: string | null;
    }
  ): void {
    if (this.config.maxLabels <= 1 || rankedCategories.length <= 1) {
      return;
    }

    const primaryScore = primaryCandidate.score;

    for (let i = 1; i < rankedCategories.length && selectedLabels.length < this.config.maxLabels; i++) {
      const candidate = rankedCategories[i];
      const scoreDifference = primaryScore - candidate.score;

      // Check if candidate meets secondary label criteria
      if (
        candidate.score >= this.config.minSecondaryConfidence &&
        scoreDifference <= this.thresholds.secondaryLabelMinGap
      ) {
        // Check if combination is allowed
        if (this.isCombinationAllowed(primaryCandidate.category, candidate.category)) {
          const secondaryLabel: SelectedLabel = {
            category: candidate.category,
            subtype: candidate.selectedSubtypeId || null,
            confidence: candidate.confidence,
            score: candidate.score,
            isPrimary: false,
            labelOrder: selectedLabels.length + 1,
            selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${this.thresholds.secondaryLabelMinGap}) and above minimum confidence (${this.config.minSecondaryConfidence})`,
          };
          selectedLabels.push(secondaryLabel);
        }
      }
    }
  }

  /**
   * Check if category combination is allowed based on configuration
   */
  private isCombinationAllowed(primaryCategory: string, candidateCategory: string): boolean {
    if (primaryCategory === candidateCategory) {
      return true;
    }

    // If strict mode is enabled and combinations are specified, only allow explicit combinations
    if (this.config.strictCombinationMode && this.config.allowedCombinations.length > 0) {
      const combination1 = `${primaryCategory}+${candidateCategory}`;
      const combination2 = `${candidateCategory}+${primaryCategory}`;
      return (
        this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2)
      );
    }

    // If no combinations specified, allow all (default permissive mode)
    if (this.config.allowedCombinations.length === 0) {
      return true;
    }

    // If combinations are specified but not in strict mode, still check them (current config has financial+actionable)
    const combination1 = `${primaryCategory}+${candidateCategory}`;
    const combination2 = `${candidateCategory}+${primaryCategory}`;
    const isExplicitlyAllowed =
      this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2);

    // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
    return isExplicitlyAllowed || !this.config.strictCombinationMode;
  }

  /**
   * Update category decisions based on selection results
   */
  private updateCategoryDecisions(
    candidateScores: Record<string, CategoryScore>,
    selectedLabels: SelectedLabel[]
  ): void {
    const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));

    for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
      const score = scoreData.score || 0;

      if (selectedCategoryNames.has(categoryCode)) {
        // Selected categories get decision based on confidence
        if (score >= this.thresholds.highConfidence) {
          scoreData.decision = 'positive';
          scoreData.decisionRationale = `High confidence (${score} >= ${this.thresholds.highConfidence}) - finalized without AI`;
        } else if (score >= this.thresholds.mediumConfidence) {
          scoreData.decision = 'candidate';
          scoreData.decisionRationale = `Medium confidence (${score} >= ${this.thresholds.mediumConfidence}) - may need AI validation`;
        } else {
          scoreData.decision = 'candidate';
          scoreData.decisionRationale = `Low confidence (${score} >= ${this.thresholds.lowConfidence}) - needs AI classification`;
        }
      } else {
        // Non-selected categories are rejected
        scoreData.decision = 'rejected';
        if (score < this.thresholds.lowConfidence) {
          scoreData.decisionRationale = `Below minimum threshold (${score} < ${this.thresholds.lowConfidence})`;
        } else {
          scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
        }
      }
    }
  }

  /**
   * Determine if AI classification is needed based on selected labels
   */
  private determineAiClassificationNeed(selectedLabels: SelectedLabel[]): boolean {
    if (selectedLabels.length === 0) {
      return true; // No labels selected - need AI
    }

    // Check if primary label has high confidence (can skip AI)
    const primaryLabel = selectedLabels.find((label) => label.isPrimary);
    if (primaryLabel && primaryLabel.score >= this.thresholds.highConfidence) {
      return false; // High confidence primary - skip AI
    }

    // Check if any label is below medium confidence (needs AI)
    const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < this.thresholds.mediumConfidence);
    if (hasLowConfidenceLabel) {
      return true; // Has low confidence labels - need AI
    }

    // Conservative approach for medium confidence range
    return true;
  }

  /**
   * Create selection summary for downstream processing
   */
  private createSelectionSummary(
    selectedLabels: SelectedLabel[],
    rankedCategories: Array<{ category: string; score: number; confidence: number; rationale: string }>,
    needsAiClassification: boolean
  ): SelectionSummary {
    if (selectedLabels.length === 0) {
      return {
        primaryCategory: '',
        secondaryCategories: [],
        rejectedCategories: rankedCategories.map((cat) => cat.category),
        totalCandidates: rankedCategories.length,
        selectionReasoning: 'No labels met minimum confidence threshold',
      };
    }

    const primaryCategory = selectedLabels.find((label) => label.isPrimary)?.category || selectedLabels[0].category;
    const secondaryCategories = selectedLabels.filter((label) => !label.isPrimary).map((label) => label.category);
    const selectedCategorySet = new Set([primaryCategory, ...secondaryCategories]);
    const rejectedCategories = rankedCategories
      .filter((cat) => !selectedCategorySet.has(cat.category))
      .map((cat) => cat.category);

    const confidences = selectedLabels.map((label) => label.confidence);
    const selectionMethod = selectedLabels.length === 1 ? 'single_label' : 'multi_label';

    return {
      primaryCategory,
      secondaryCategories,
      rejectedCategories,
      totalCandidates: rankedCategories.length,
      selectionReasoning: `Selected ${selectedLabels.length} labels (${selectionMethod}) with confidence range [${Math.min(...confidences)}, ${Math.max(...confidences)}]. ${needsAiClassification ? 'AI classification needed.' : 'High confidence - no AI needed.'}`,
    };
  }

  /**
   * Create result for no selection case
   */
  private createNoSelectionResult(
    startTime: number,
    rankedCategories: Array<{ category: string; score: number; confidence: number; rationale: string }>
  ): MultiLabelSelectionResult {
    return {
      selectedLabels: [],
      needsAiClassification: true,
      selectionSummary: {
        primaryCategory: '',
        secondaryCategories: [],
        rejectedCategories: rankedCategories.map((cat) => cat.category),
        totalCandidates: rankedCategories.length,
        selectionReasoning: 'No labels met minimum confidence threshold - AI classification needed',
      },
      processingDurationMs: Date.now() - startTime,
    };
  }
}

