toolUseResult.originalFile:
/**
 * T032: Attribute Influence Stage Implementation
 *
 * Applies role-based bonuses and penalties based on the attribute relevance matrix.
 * Implements sophisticated role enforcement per SCORING_LOGIC.md.
 *
 * Reference: AttributeInfluenceNode.js (role-based bonuses, bounded adjustments)
 * Config: processing_config.attribute_relevance (CORE/PRIMARY_BOOST/SECONDARY_BOOST/DISAMBIGUATOR/FILTER roles)
 * Logic: Attribute bonus mapping and role enforcement per SCORING_LOGIC.md
 */

import { EmailMessage } from '../types/email-message';
import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';
import { ClassificationSession } from '../types/classification-session';
import { ClassificationResult } from '../types/classification-result';

/**
 * Result of attribute influence stage with role-based bonuses
 */
export interface AttributeInfluenceResult {
  influence_applications: AttributeInfluenceApplication[];
  processing_duration_ms: number;
  configuration_references: {
    attribute_relevance_path: string;
    bonus_config_path: string;
  };
  // Preserve previous stage data
  [key: string]: unknown;
}

/**
 * Individual attribute influence application
 */
export interface AttributeInfluenceApplication {
  category: string;
  subtype?: string;
  attribute: string;
  role: AttributeRole;
  bonus_applied: number;
  score_before: number;
  score_after: number;
  cap_reached: boolean;
  application_metadata: {
    detection_confidence: number;
    role_source: 'category' | 'subtype';
    cap_type: 'role_cap' | 'no_cap';
  };
}

/**
 * Role bonus configuration
 */
interface RoleBonusConfig {
  bonus: number;
  cap: number;
}

/**
 * Execute attribute influence stage (canonical signature)
 *
 * Applies role-based bonuses to categories based on detected attributes
 * and the attribute relevance matrix configuration.
 *
 * Mutates the result object in place by updating scoreBreakdown and attributeContext.
 */
// FIXME looks like some unused parameters should be documented as common interface parameters
export function executeAttributeInfluence(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: CategoryConfiguration
): void {
  const startTime = Date.now();

  // Validate configuration
  if (!config.processing_config?.attribute_relevance) {
    throw new Error('Attribute relevance configuration not found');
  }

  // Validate attribute bonus configuration exists
  if (!config.processing_config?.attributes?.attribute_bonus_map) {
    throw new Error('Attribute bonus configuration not found');
  }

  const attributeRelevance = config.processing_config.attribute_relevance;

  const influenceApplications: AttributeInfluenceApplication[] = [];

  // Process each detected attribute from result.attributeContext
  for (const [attributeName, metadata] of Object.entries(result.attributeContext.detectionMetadata)) {
    // Apply influence for each category
    for (const categoryName of Object.keys(config.processing_config.top_level_categories)) {
      const categoryConfig = attributeRelevance[categoryName];
      if (!categoryConfig) continue;

      // Check category-level roles - handle union type safely
      const categoryRole =
        'category_roles' in categoryConfig ? categoryConfig.category_roles?.[attributeName] : undefined;
      if (categoryRole) {
        validateAttributeRole(categoryRole);

        const application = applyAttributeInfluence(
          categoryName,
          undefined, // No subtype for category-level
          attributeName,
          categoryRole,
          metadata.confidence,
          { bonus: getRoleBonusValue(categoryRole), cap: 1.0 },
          'category'
        );

        influenceApplications.push(application);
      }

      // Check subtype-level roles - handle union type safely
      if ('subtypes' in categoryConfig && categoryConfig.subtypes) {
        for (const [subtypeName, subtypeConfig] of Object.entries(categoryConfig.subtypes)) {
          const subtypeRole = subtypeConfig.roles?.[attributeName];
          if (subtypeRole) {
            validateAttributeRole(subtypeRole);

            const application = applyAttributeInfluence(
              categoryName,
              subtypeName,
              attributeName,
              subtypeRole,
              metadata.confidence,
              { bonus: getRoleBonusValue(subtypeRole), cap: 1.0 },
              'subtype'
            );

            influenceApplications.push(application);
          }
        }
      }
    }
  }

  // Apply role caps by category and role type
  const defaultRoleCaps = {
    CORE: 50,
    PRIMARY_BOOST: 30,
    SECONDARY_BOOST: 16,
    DISAMBIGUATOR: 10,
    FILTER: 40, // Absolute value for negative bonuses
  };
  const cappedApplications = applyRoleCapsByRole(influenceApplications, defaultRoleCaps);

  const duration = Date.now() - startTime;

  // Mutate result: Update attributeContext with influence applications (convert to AttributeContext format)
  result.attributeContext.influenceApplications = cappedApplications.map((app) => ({
    targetCategory: app.subtype ? `${app.category}.${app.subtype}` : app.category,
    attributeUsed: app.attribute,
    roleType: app.role,
    scoreImpact: app.bonus_applied,
    applicationReason: `${app.role} bonus applied`,
    appliedDuringParallelExecution: false,
    dependentOnAttributes: [],
    influenceTimestamp: new Date(),
    influenceReliability: app.application_metadata.detection_confidence,
    historicalAccuracy: 0.85, // Default historical accuracy
  }));

  // Update scoreBreakdown with attribute influence scores
  for (const app of cappedApplications) {
    const categoryKey = app.subtype ? `${app.category}.${app.subtype}` : app.category;
    if (!result.scoreBreakdown.categoryScores[categoryKey]) {
      // FIXME double-check if this initialization logic is in initialization.ts
      result.scoreBreakdown.categoryScores[categoryKey] = {
        baseScore: 0,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: 0,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    }
    result.scoreBreakdown.categoryScores[categoryKey].attributeInfluenceScore += app.bonus_applied;
  }

  // Update result processing duration
  result.processingDurationMs += duration;

  // Add parallel stage result tracking
  result.parallelStageResults.push({
    stageId: `attribute_influence_${result.id}`,
    stageName: 'attribute_influence',
    executionTimeMs: duration,
    parallelWithStages: [],
    dependentOnStages: ['attribute_detection'],
    cacheHitsCount: 0,
    errorCount: 0,
  });

  // Update explainability trace (convert to ExplainabilityTrace.AttributeInfluenceResult format)
  // Filter to only include valid role types for explainability
  const validRoleTypes: Array<'CORE' | 'PRIMARY_BOOST' | 'SECONDARY_BOOST' | 'DISAMBIGUATOR' | 'FILTER'> = [
    'CORE',
    'PRIMARY_BOOST',
    'SECONDARY_BOOST',
    'DISAMBIGUATOR',
    'FILTER',
  ];

  result.explainabilityTrace.attributeInfluence = cappedApplications
    .filter((app) => validRoleTypes.includes(app.role as (typeof validRoleTypes)[number]))
    .map((app) => ({
      targetCategory: app.subtype ? `${app.category}.${app.subtype}` : app.category,
      attributeUsed: app.attribute,
      roleType: app.role as 'CORE' | 'PRIMARY_BOOST' | 'SECONDARY_BOOST' | 'DISAMBIGUATOR' | 'FILTER',
      bonusAmount: app.bonus_applied,
      scoreBefore: app.score_before,
      scoreAfter: app.score_after,
      capApplied: app.cap_reached,
      reason: `${app.role} bonus of ${app.bonus_applied} applied to ${app.category}${app.subtype ? `.${app.subtype}` : ''}`,
    }));
  result.explainabilityTrace.stageTimings['attribute_influence'] = duration;
  result.explainabilityTrace.configurationRefs['attribute_influence'] = 'processing_config.attribute_relevance';
}

/**
 * Apply attribute influence for a specific category/subtype combination
 */
function applyAttributeInfluence(
  category: string,
  subtype: string | undefined,
  attribute: string,
  role: AttributeRole,
  confidence: number,
  bonusConfig: RoleBonusConfig,
  roleSource: 'category' | 'subtype'
): AttributeInfluenceApplication {
  const baseBonusAmount = bonusConfig.bonus;

  // For now, we assume score_before is 0 since we don't have actual scores yet
  // In the full pipeline, this would come from previous stages
  const scoreBefore = 0;

  // Apply the bonus (can be negative for FILTER roles)
  const bonusApplied = baseBonusAmount;
  const scoreAfter = scoreBefore + bonusApplied;

  return {
    category,
    subtype,
    attribute,
    role,
    bonus_applied: bonusApplied,
    score_before: scoreBefore,
    score_after: scoreAfter,
    cap_reached: false, // Will be updated in applyRoleCaps
    application_metadata: {
      detection_confidence: confidence,
      role_source: roleSource,
      cap_type: 'no_cap',
    },
  };
}

/**
 * Get role-based bonus value matching test expectations
 */
function getRoleBonusValue(role: AttributeRole): number {
  switch (role) {
  case 'CORE':
    return 25;
  case 'PRIMARY_BOOST':
    return 15;
  case 'SECONDARY_BOOST':
    return 8;
  case 'DISAMBIGUATOR':
    return 5;
  case 'FILTER':
    return -20;
  default:
    return 0;
  }
}

/**
 * Apply role-based caps to influence applications
 */
function applyRoleCapsByRole(
  applications: AttributeInfluenceApplication[],
  roleCaps: Record<string, number>
): AttributeInfluenceApplication[] {
  // Group applications by category, subtype (if any), and role for capping
  const groupedApplications = new Map<string, AttributeInfluenceApplication[]>();

  for (const app of applications) {
    const subtypeKey = app.subtype ? `:${app.subtype}` : '';
    const key = `${app.category}${subtypeKey}:${app.role}`;
    if (!groupedApplications.has(key)) {
      groupedApplications.set(key, []);
    }
    groupedApplications.get(key)!.push(app);
  }

  // Apply caps within each group
  const cappedApplications: AttributeInfluenceApplication[] = [];

  for (const [groupKey, groupApps] of Array.from(groupedApplications.entries())) {
    // Extract role from group key
    const [, roleStr] = groupKey.split(':').slice(-2);
    const role = roleStr as AttributeRole;

    // Get role cap
    const cap = roleCaps[role];

    if (!cap) {
      // No cap for this role, add all applications
      cappedApplications.push(...groupApps);
      continue;
    }

    // Apply role-based capping
    let totalBonusApplied = 0;

    for (const app of groupApps) {
      // Handle negative bonuses (FILTER roles) differently
      if (app.bonus_applied < 0) {
        // For negative bonuses, cap is about preventing too much penalty
        if (Math.abs(totalBonusApplied) + Math.abs(app.bonus_applied) <= cap) {
          // Apply full penalty
          cappedApplications.push(app);
          totalBonusApplied += app.bonus_applied;
        } else if (Math.abs(totalBonusApplied) < cap) {
          // Apply partial penalty to reach cap
          const remainingCap = cap - Math.abs(totalBonusApplied);
          const cappedApp = {
            ...app,
            bonus_applied: -remainingCap,
            score_after: app.score_before - remainingCap,
            cap_reached: true,
            application_metadata: {
              ...app.application_metadata,
              cap_type: 'role_cap' as const,
            },
          };
          cappedApplications.push(cappedApp);
          totalBonusApplied = -cap;
        } else {
          // Cap already reached, no more penalty
          const cappedApp = {
            ...app,
            bonus_applied: 0,
            score_after: app.score_before,
            cap_reached: true,
            application_metadata: {
              ...app.application_metadata,
              cap_type: 'role_cap' as const,
            },
          };
          cappedApplications.push(cappedApp);
        }
      } else {
        // Handle positive bonuses
        if (totalBonusApplied + app.bonus_applied <= cap) {
          // Apply full bonus
          cappedApplications.push(app);
          totalBonusApplied += app.bonus_applied;
        } else if (totalBonusApplied < cap) {
          // Apply partial bonus to reach cap
          const remainingCap = cap - totalBonusApplied;
          const cappedApp = {
            ...app,
            bonus_applied: remainingCap,
            score_after: app.score_before + remainingCap,
            cap_reached: true,
            application_metadata: {
              ...app.application_metadata,
              cap_type: 'role_cap' as const,
            },
          };
          cappedApplications.push(cappedApp);
          totalBonusApplied = cap;
        } else {
          // Cap already reached, mark as capped with zero bonus
          const cappedApp = {
            ...app,
            bonus_applied: 0,
            score_after: app.score_before,
            cap_reached: true,
            application_metadata: {
              ...app.application_metadata,
              cap_type: 'role_cap' as const,
            },
          };
          cappedApplications.push(cappedApp);
        }
      }
    }
  }

  return cappedApplications;
}

/**
 * Validate that a role is a valid AttributeRole
 */
function validateAttributeRole(role: string): asserts role is AttributeRole {
  const validRoles: AttributeRole[] = [
    'CORE',
    'PRIMARY_BOOST',
    'SECONDARY_BOOST',
    'DISAMBIGUATOR',
    'FILTER',
    'STRUCTURAL',
    'DERIVED_LINK',
    'NEUTRAL',
  ];

  if (!validRoles.includes(role as AttributeRole)) {
    throw new Error(`Invalid attribute role: ${role}`);
  }
}

import { z } from 'zod';
import { EmailMessage, StrongIndicatorResult, ClassificationSession, ClassificationResult } from '../types';
import {
  extractDomainFromEmail,
  findMatchingDomain,
  findMatchingKeywords,
  extractEmailBodyText,
} from '../utils/email-utils';
import { ConfidenceThresholds, ConfidenceThresholdsSchema } from './types';

/**
 * Strong Indicators Stage
 *
 * Implements diminishing returns seeding per SCORING_LOGIC.md "Strong Indicator Seeding" section.
 * High-weight signals that provide strong category hints, applied with diminishing returns
 * across multiple dimensions (subject, from_domain, body).
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => void
 *
 * Logic:
 * - seed = Σ weighted_matches
 * - Diminishing returns per dimension: first full, rest * 0.5
 * - strong_indicator_seed = max(existing_seed, seed)
 * - Applied after hard assertions before subtype accumulation
 * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
 */

export interface StrongIndicatorConfig {
  from_domains_ref?: {
    source_group: string;
    confidence: 'high' | 'medium';
  };
  subject_contains?: string[];
  body_contains?: string[];
}

export interface StrongIndicatorStageConfig {
  confidenceThresholds: ConfidenceThresholds;
  categorySignals: Record<string, { strong_indicators?: StrongIndicatorConfig }>;
  domainLookup: Record<
    string,
    {
      high_confidence: Array<{ domain: string; type?: string }>;
      medium_confidence: Array<{ domain: string; type?: string }>;
      low_confidence: Array<{ domain: string; type?: string }>;
    }
  >;
  // Weight for strong indicators (typically 8-12 range for medium-high confidence)
  strongIndicatorBaseWeight: number;
  // Diminishing returns factor for subsequent matches in same dimension
  diminishingReturnsFactor: number;
}

/**
 * Executes strong indicators stage of email classification
 *
 * CANONICAL SIGNATURE: Mutates result object instead of returning values
 *
 * @param email The email message to classify
 * @param session Classification session (batch-level metadata)
 * @param result Classification result to update (mutated in place)
 * @param config Configuration containing category signals and thresholds
 */
// FIXME some parameters appear unused - should these just be documented as common interface parameters?
export function executeStrongIndicators(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: StrongIndicatorStageConfig
): void {
  const startTime = Date.now();

  const categoriesWithStrongIndicators: string[] = [];
  const indicatorResults: StrongIndicatorResult[] = [];

  const baseWeight = config.strongIndicatorBaseWeight;
  const diminishingFactor = config.diminishingReturnsFactor;

  // Process each category that has strong indicators configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.strong_indicators) {
      continue;
    }

    const strongIndicators = categoryConfig.strong_indicators;
    // Read existing seed from result.scoreBreakdown
    const existingSeed = result.scoreBreakdown.categoryScores[categoryName]?.strongIndicatorScore || 0;
    let categoryHadIndicator = false;
    let newSeedScore = existingSeed;

    // Track matches per dimension for diminishing returns
    const dimensionMatches = {
      from_domain: 0,
      subject_contains: 0,
      body_contains: 0,
    };

    // Check from_domains_ref (domain-based strong indicators)
    if (strongIndicators.from_domains_ref) {
      const { source_group, confidence } = strongIndicators.from_domains_ref;

      const domainGroup = config.domainLookup[source_group];
      if (domainGroup) {
        const emailDomain = extractDomainFromEmail(email.from.email);
        const matchedDomain = findMatchingDomain(emailDomain, domainGroup, confidence);

        if (matchedDomain) {
          dimensionMatches.from_domain++;
          const isFirstMatch = dimensionMatches.from_domain === 1;
          const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
          const proposedSeed = newSeedScore + effectiveWeight;

          indicatorResults.push({
            category: categoryName,
            indicatorType: 'from_domain',
            matchedValue: matchedDomain.domain,
            seedScore: effectiveWeight,
            diminishingReturnsApplied: !isFirstMatch,
            existingSeedScore: newSeedScore,
            finalSeedScore: proposedSeed,
            reason: `Email from domain '${emailDomain}' matches ${confidence}-confidence domain '${matchedDomain.domain}' in group '${source_group}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
          });

          newSeedScore = Math.max(newSeedScore, proposedSeed);
          categoryHadIndicator = true;
        }
      }
    }

    // Check subject_contains
    if (strongIndicators.subject_contains && email.subject) {
      const matchedKeywords = findMatchingKeywords(email.subject, strongIndicators.subject_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.subject_contains++;
        const isFirstMatch = dimensionMatches.subject_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'subject_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Subject '${email.subject}' contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Check body_contains
    if (strongIndicators.body_contains) {
      const bodyText = extractEmailBodyText(email);
      const matchedKeywords = findMatchingKeywords(bodyText, strongIndicators.body_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.body_contains++;
        const isFirstMatch = dimensionMatches.body_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'body_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Body text contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Update seed score using max logic (strong_indicator_seed = max(existing_seed, seed))
    if (categoryHadIndicator) {
      // Update result.scoreBreakdown (mutate in place)
      if (!result.scoreBreakdown.categoryScores[categoryName]) {
        result.scoreBreakdown.categoryScores[categoryName] = {
          baseScore: 0,
          hardAssertionBonus: 0,
          strongIndicatorScore: 0,
          ruleScore: 0,
          attributeInfluenceScore: 0,
          finalScore: 0,
          parallelComputedComponents: [],
          computationDurationMs: 0,
          cacheHits: [],
          scoreAggregationSteps: [],
          cappingApplied: false,
        };
      }

      result.scoreBreakdown.categoryScores[categoryName].strongIndicatorScore = newSeedScore;
      result.scoreBreakdown.categoryScores[categoryName].finalScore = Math.max(
        result.scoreBreakdown.categoryScores[categoryName].finalScore,
        newSeedScore
      );
      categoriesWithStrongIndicators.push(categoryName);
    }
  }

  // Update result.explainabilityTrace with strong indicators (mutate in place)
  result.explainabilityTrace.strongIndicators = indicatorResults;

  // Track stage timing
  const durationMs = Date.now() - startTime;

  // Store timing in explainability trace
  result.explainabilityTrace.stageTimings['strong_indicators'] = durationMs;
  result.explainabilityTrace.configurationRefs['strong_indicators'] = 'category_signals.*.strong_indicators';

  // Update processing duration
  result.processingDurationMs += durationMs;
}

/**
 * Zod schema for validating strong indicator configuration
 */
export const StrongIndicatorConfigSchema = z
  .object({
    from_domains_ref: z
      .object({
        source_group: z.string(),
        confidence: z.enum(['high', 'medium']),
      })
      .optional(),
    subject_contains: z.array(z.string()).optional(),
    body_contains: z.array(z.string()).optional(),
  })
  .refine(
    (config) => {
      // At least one indicator type must be configured
      return !!(config.from_domains_ref || config.subject_contains || config.body_contains);
    },
    {
      message: 'At least one strong indicator type must be configured',
    }
  );

export const StrongIndicatorStageConfigSchema = z.object({
  confidenceThresholds: ConfidenceThresholdsSchema,
  categorySignals: z.record(
    z.object({
      strong_indicators: StrongIndicatorConfigSchema.optional(),
    })
  ),
  domainLookup: z.record(
    z.object({
      high_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      medium_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      low_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
    })
  ),
  strongIndicatorBaseWeight: z.number().min(0).default(10), // Typical range 8-12
  diminishingReturnsFactor: z.number().min(0).max(1).default(0.5), // First full, rest * 0.5
});

