   145→/**
   146→ * Detect pattern-based attributes using configured detectors
   147→ */
   148→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   149→  const detectors = config.attributes?.detectors || [];
   150→  const detectedAttributes: DetectedAttribute[] = [];
   151→
   152→  for (const detector of detectors) {
   153→    try {
   154→      const detection = applyDetector(email, detector);
   155→      if (detection.detected) {
   156→        detectedAttributes.push({
   157→          attribute_name: detector.attribute,
   158→          attribute_value: detection.value as string | number | boolean,
   159→          detection_method: 'pattern',
   160→          detection_evidence: detection.evidence || 'Pattern match',
   161→          confidence: 0.8, // Default confidence for pattern matches
   162→        });
   163→      }
   164→    } catch (error) {
   165→      // Log error but continue processing
   166→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   167→    }
   168→  }
   169→
   170→  return detectedAttributes;
   171→}
   172→
   173→/**
   174→ * Apply individual detector pattern to email content
   175→ */
   176→function applyDetector(
   177→  email: EmailMessage,
   178→  detector: AttributeDetector
   179→): { detected: boolean; value?: unknown; evidence?: string } {
   180→  const { field, operation, values } = detector;
   181→
   182→  // Get the field content to search
   183→  let searchContent = '';
   184→  switch (field) {
   185→  case 'body':
   186→    searchContent = extractEmailBodyText(email);
   187→    break;
   188→  case 'subject':
   189→    searchContent = email.subject || '';
   190→    break;
   191→  case 'from.address':
   192→    searchContent = email.from?.email || '';
   193→    break;
   194→  case 'from.name':
   195→    searchContent = email.from?.name || '';
   196→    break;
   197→  default:
   198→    console.warn(`Unknown field type for detector: ${field}`);
   199→    return { detected: false };
   200→  }
   201→
   202→  // Apply detection operation
   203→  switch (operation) {
   204→  case 'contains_any':
   205→    for (const value of values) {
   206→      if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   207→        return {
   208→          detected: true,
   209→          value: true,
   210→          evidence: `Found "${value}" in ${field}`,
   211→        };
   212→      }
   213→    }
   214→    break;
   215→
   216→  case 'regex_any':
   217→    for (const pattern of values) {
   218→      try {
   219→        const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   220→        const match = searchContent.match(regex);
   221→        if (match) {
   222→          // For amount patterns, try to match the longest currency pattern
   223→          let bestMatch = match[0];
   224→          if (pattern.includes('\\$\\d+')) {
   225→            // Special handling for currency amounts - match full amounts with decimals
   226→            const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   227→            const fullMatches = searchContent.match(fullAmountRegex);
   228→            if (fullMatches && fullMatches.length > 0) {
   229→              bestMatch = fullMatches[0]; // Use the first full amount match
   230→            }
   231→          }
   232→          return {
   233→            detected: true,
   234→            value: true,
   235→            evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   236→          };
   237→        }
   238→      } catch (error) {
   239→        console.warn(`Invalid regex pattern: ${pattern}`, error);
   240→        continue;
   241→      }
   242→    }
   243→    break;
   244→
   245→  case 'starts_with':
   246→    for (const value of values) {
   247→      if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   248→        return {
   249→          detected: true,
   250→          value: true,
   251→          evidence: `${field} starts with "${value}"`,
   252→        };
   253→      }
   254→    }
   255→    break;
   256→
   257→  case 'ends_with':
   258→    for (const value of values) {
   259→      if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   260→        return {
   261→          detected: true,
   262→          value: true,
   263→          evidence: `${field} ends with "${value}"`,
   264→        };
   265→      }
   266→    }
   267→    break;
   268→
   269→  default:
   270→    console.warn(`Unknown operation type: ${operation}`);
   271→  }
   272→
   273→  return { detected: false };
   274→}
