   279→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   280→  const settings = config.settings?.attribute_processing;
   281→  const detectedAttributes: DetectedAttribute[] = [];
   282→
   283→  // Derive self_sent attribute (if enabled, default true)
