   285→  if (detectSelfSent) {
   286→    const selfSent = deriveSelfSent(email);
   287→    if (selfSent) {
   288→      detectedAttributes.push(selfSent);
   289→    }
   290→  }
   291→
   292→  // Domain-based derivations (if enabled, default true)
   293→  const resolveDomains = !settings || settings.resolve_domains !== false;
   294→  if (resolveDomains) {
   295→    // Derive from_financial_institution attribute
