   317→/**
   318→ * Derive self_sent attribute - email sent from user to self
   319→ */
   320→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   321→  const userAddresses = getUserAddresses();
   322→  const fromAddress = email.from?.email?.toLowerCase();
   323→
   324→  // Check if from address is user address
   325→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   326→    return null;
   327→  }
   328→
   329→  // Check if all recipients are user addresses
   330→  const allRecipients: string[] = [];
   331→  if (email.to) {
   332→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   333→  }
   334→  if (email.cc) {
   335→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   336→  }
   337→  if (email.bcc) {
   338→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   339→  }
   340→
   341→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   342→
   343→  // Check for List-Id header (exclude mailing lists)
   344→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   345→
   346→  if (allRecipientsAreUser && !hasListId) {
   347→    return {
   348→      attribute_name: 'self_sent',
   349→      attribute_value: true,
   350→      detection_method: 'derived',
   351→      detection_evidence: 'All recipients match user addresses',
   352→      confidence: 0.9,
   353→    };
   354→  }
   355→
   356→  return null;
   357→}
   358→
   359→/**
   360→ * Derive from_financial_institution attribute using domain lookup
   361→ */
   362→function deriveFromFinancialInstitution(
   363→  email: EmailMessage,
   364→  config: AttributeDetectionStageConfig
   365→): DetectedAttribute | null {
   366→  const fromAddress = email.from?.email?.toLowerCase();
   367→  if (!fromAddress) return null;
   368→
   369→  const fromDomain = extractBaseDomain(fromAddress);
   370→  const financialDomains = getFinancialDomains(config);
   371→
   372→  if (financialDomains.includes(fromDomain)) {
   373→    return {
   374→      attribute_name: 'from_financial_institution',
   375→      attribute_value: true,
   376→      detection_method: 'domain_lookup',
   377→      detection_evidence: fromDomain,
   378→      confidence: 0.85,
   379→    };
   380→  }
   381→
   382→  return null;
   383→}
   384→
   385→/**
   386→ * Derive from_newsletter_source attribute
   387→ */
   388→function deriveFromNewsletterSource(
   389→  email: EmailMessage,
   390→  config: AttributeDetectionStageConfig
   391→): DetectedAttribute | null {
   392→  const fromAddress = email.from?.email?.toLowerCase();
   393→  if (!fromAddress) return null;
   394→
   395→  const fromDomain = extractBaseDomain(fromAddress);
   396→  const newsletterDomains = getNewsletterDomains(config);
   397→
   398→  // Check domain match
   399→  if (newsletterDomains.includes(fromDomain)) {
   400→    return {
   401→      attribute_name: 'from_newsletter_source',
   402→      attribute_value: true,
   403→      detection_method: 'domain_lookup',
   404→      detection_evidence: fromDomain,
   405→      confidence: 0.8,
   406→    };
   407→  }
   408→
   409→  // Check List-Id header presence
   410→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   411→  if (hasListId) {
   412→    return {
   413→      attribute_name: 'from_newsletter_source',
   414→      attribute_value: true,
   415→      detection_method: 'derived',
   416→      detection_evidence: 'List-Id header present',
   417→      confidence: 0.85,
   418→    };
   419→  }
   420→
   421→  return null;
   422→}
   423→
   424→/**
   425→ * Derive from_logistics_carrier attribute
   426→ */
   427→function deriveFromLogisticsCarrier(
   428→  email: EmailMessage,
   429→  config: AttributeDetectionStageConfig
   430→): DetectedAttribute | null {
   431→  const fromAddress = email.from?.email?.toLowerCase();
   432→  if (!fromAddress) return null;
   433→
   434→  const fromDomain = extractBaseDomain(fromAddress);
   435→  const logisticsDomains = getLogisticsDomains(config);
   436→
   437→  if (logisticsDomains.includes(fromDomain)) {
   438→    return {
   439→      attribute_name: 'from_logistics_carrier',
   440→      attribute_value: true,
   441→      detection_method: 'domain_lookup',
   442→      detection_evidence: fromDomain,
   443→      confidence: 0.85,
   444→    };
   445→  }
   446→
   447→  return null;
   448→}
   449→
   450→/**
   451→ * Extract base domain from email address
   452→ */
   453→function extractBaseDomain(email: string): string {
   454→  const domainPart = email.split('@')[1];
   455→  if (!domainPart) return '';
