/**
 * Attribute Detection Stage
 *
 * Stage 4 of the EmailCategorizer pipeline. Detects and derives contextual attributes
 * from email content and metadata that will influence category scoring in the next stage.
 *
 * Implements pattern-based and derived attribute detection per SCORING_LOGIC.md
 * "Attribute Detectors & Derived Attributes" section.
 */

import { EmailMessage, ProcessingConfig, AttributeDetector, DerivedAttribute } from '../types';
import { ClassificationSession } from '../types/classification-session';
import { ClassificationResult } from '../types/classification-result';
import { extractEmailBodyText } from '../utils/email-utils';
import { createClassificationSession, createClassificationResult } from '../utils/initialization';

/**
 * Individual detected attribute result
 */
export interface DetectedAttribute {
  attribute_name: string;
  attribute_value: boolean | string | number;
  detection_method: 'pattern' | 'derived' | 'domain_lookup';
  detection_evidence: string;
  confidence: number;
}

/**
 * Result of attribute detection stage
 */
export interface AttributeDetectionResult {
  detected_attributes: DetectedAttribute[];
  processing_duration_ms: number;
  parallel_processed: boolean;
  dependencies: string[];
  // Preserve previous stage data
  [key: string]: unknown;
}

/**
 * Attribute Detection Stage Configuration
 */
export interface AttributeDetectionStageConfig {
  settings: {
    attribute_processing: {
      detect_self_sent: boolean;
      resolve_domains: boolean;
      derive_context_flags: boolean;
    };
  };
  attributes: {
    schema: Record<string, unknown>;
    detectors: AttributeDetector[];
    derived: Record<string, DerivedAttribute>;
    attribute_bonus_map?: Record<string, Record<string, number>>;
  };
  performance_cache?: {
    financial_domains?: string[];
    newsletter_domains?: string[];
    logistics_domains?: string[];
  };
}

/**
 * Execute attribute detection stage function (canonical signature)
 *
 * Mutates the result object in place by populating attributeContext.detectedAttributes
 * and updating session performance metrics.
 */
export function executeAttributeDetection(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AttributeDetectionStageConfig
): void {
  const startTime = Date.now();

  const detectedAttributes: DetectedAttribute[] = [];

  // Apply pattern-based detectors
  const patternAttributes = detectPatternAttributes(email, config);
  detectedAttributes.push(...patternAttributes);

  // Apply derived attribute logic
  const derivedAttributes = detectDerivedAttributes(email, config);
  detectedAttributes.push(...derivedAttributes);

  // Mutate result: Update attribute context with detected attributes
  for (const attr of detectedAttributes) {
    result.attributeContext.detectionMetadata[attr.attribute_name] = {
      confidence: attr.confidence,
      detectionMethod: attr.detection_method,
      evidence: attr.detection_evidence,
      detectedAt: new Date(),
    };
  }

  // Track performance in session
  const duration = Date.now() - startTime;
  if (!session.performanceMetrics) {
    session.performanceMetrics = {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    };
  }
  session.performanceMetrics.parallelStagesCount += 1;

  // Update result processing duration
  result.processingDurationMs += duration;

  // Add parallel stage result tracking
  result.parallelStageResults.push({
    stageId: `attribute_detection_${result.id}`,
    stageName: 'attribute_detection',
    executionTimeMs: duration,
    parallelWithStages: [], // This stage can run in parallel
    dependentOnStages: ['rule_scoring'], // Depends on earlier stages
    cacheHitsCount: 0,
    errorCount: 0,
  });

  // Update explainability trace (convert to ExplainabilityTrace.AttributeDetectionResult format)
  result.explainabilityTrace.attributeDetection = detectedAttributes.map((attr) => ({
    attribute: attr.attribute_name,
    detected: true,
    detectionMethod:
      attr.detection_method === 'pattern' || attr.detection_method === 'domain_lookup' ? 'direct' : 'derived',
    sourceField: attr.detection_method === 'pattern' ? 'email_body_or_subject' : undefined,
    derivationLogic:
      attr.detection_method === 'derived' || attr.detection_method === 'domain_lookup'
        ? attr.detection_evidence
        : undefined,
    confidence: attr.confidence,
    parallelProcessed: true,
    dependencies: [],
    reason: attr.detection_evidence,
  }));

  result.explainabilityTrace.stageTimings['attribute_detection'] = duration;
  result.explainabilityTrace.configurationRefs['attribute_detection'] = 'attributes.detectors';
}

/**
 * Detect pattern-based attributes using configured detectors
 */
function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
  const detectors = config.attributes?.detectors || [];
  const detectedAttributes: DetectedAttribute[] = [];

  for (const detector of detectors) {
    try {
      const detection = applyDetector(email, detector);
      if (detection.detected) {
        detectedAttributes.push({
          attribute_name: detector.attribute,
          attribute_value: detection.value as string | number | boolean,
          detection_method: 'pattern',
          detection_evidence: detection.evidence || 'Pattern match',
          confidence: 0.8, // Default confidence for pattern matches
        });
      }
    } catch (error) {
      // Log error but continue processing
      console.warn(`Error applying detector for ${detector.attribute}:`, error);
    }
  }

  return detectedAttributes;
}

/**
 * Apply individual detector pattern to email content
 */
function applyDetector(
  email: EmailMessage,
  detector: AttributeDetector
): { detected: boolean; value?: unknown; evidence?: string } {
  const { field, operation, values } = detector;

  // Get the field content to search
  let searchContent = '';
  switch (field) {
  case 'body':
    searchContent = extractEmailBodyText(email);
    break;
  case 'subject':
    searchContent = email.subject || '';
    break;
  case 'from.address':
    searchContent = email.from?.email || '';
    break;
  case 'from.name':
    searchContent = email.from?.name || '';
    break;
  default:
    console.warn(`Unknown field type for detector: ${field}`);
    return { detected: false };
  }

  // Apply detection operation
  switch (operation) {
  case 'contains_any':
    for (const value of values) {
      if (searchContent.toLowerCase().includes(value.toLowerCase())) {
        return {
          detected: true,
          value: true,
          evidence: `Found "${value}" in ${field}`,
        };
      }
    }
    break;

  case 'regex_any':
    for (const pattern of values) {
      try {
        const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
        const match = searchContent.match(regex);
        if (match) {
          // For amount patterns, try to match the longest currency pattern
          let bestMatch = match[0];
          if (pattern.includes('\\$\\d+')) {
            // Special handling for currency amounts - match full amounts with decimals
            const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
            const fullMatches = searchContent.match(fullAmountRegex);
            if (fullMatches && fullMatches.length > 0) {
              bestMatch = fullMatches[0]; // Use the first full amount match
            }
          }
          return {
            detected: true,
            value: true,
            evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
          };
        }
      } catch (error) {
        console.warn(`Invalid regex pattern: ${pattern}`, error);
        continue;
      }
    }
    break;

  case 'starts_with':
    for (const value of values) {
      if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
        return {
          detected: true,
          value: true,
          evidence: `${field} starts with "${value}"`,
        };
      }
    }
    break;

  case 'ends_with':
    for (const value of values) {
      if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
        return {
          detected: true,
          value: true,
          evidence: `${field} ends with "${value}"`,
        };
      }
    }
    break;

  default:
    console.warn(`Unknown operation type: ${operation}`);
  }

  return { detected: false };
}

/**
 * Detect derived attributes using logical rules
 */
function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
  const settings = config.settings?.attribute_processing;
  const detectedAttributes: DetectedAttribute[] = [];

  // Derive self_sent attribute (if enabled, default true)
  const detectSelfSent = !settings || settings.detect_self_sent !== false;
  if (detectSelfSent) {
    const selfSent = deriveSelfSent(email);
    if (selfSent) {
      detectedAttributes.push(selfSent);
    }
  }

  // Domain-based derivations (if enabled, default true)
  const resolveDomains = !settings || settings.resolve_domains !== false;
  if (resolveDomains) {
    // Derive from_financial_institution attribute
    const financialInstitution = deriveFromFinancialInstitution(email, config);
    if (financialInstitution) {
      detectedAttributes.push(financialInstitution);
    }

    // Derive from_newsletter_source attribute
    const newsletterSource = deriveFromNewsletterSource(email, config);
    if (newsletterSource) {
      detectedAttributes.push(newsletterSource);
    }

    // Derive from_logistics_carrier attribute
    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
    if (logisticsCarrier) {
      detectedAttributes.push(logisticsCarrier);
    }
  }

  return detectedAttributes;
}

/**
 * Derive self_sent attribute - email sent from user to self
 */
function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
  const userAddresses = getUserAddresses();
  const fromAddress = email.from?.email?.toLowerCase();

  // Check if from address is user address
  if (!fromAddress || !userAddresses.includes(fromAddress)) {
    return null;
  }

  // Check if all recipients are user addresses
  const allRecipients: string[] = [];
  if (email.to) {
    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
  }
  if (email.cc) {
    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
  }
  if (email.bcc) {
    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
  }

  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));

  // Check for List-Id header (exclude mailing lists)
  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');

  if (allRecipientsAreUser && !hasListId) {
    return {
      attribute_name: 'self_sent',
      attribute_value: true,
      detection_method: 'derived',
      detection_evidence: 'All recipients match user addresses',
      confidence: 0.9,
    };
  }

  return null;
}

/**
 * Derive from_financial_institution attribute using domain lookup
 */
function deriveFromFinancialInstitution(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const financialDomains = getFinancialDomains(config);

  if (financialDomains.includes(fromDomain)) {
    return {
      attribute_name: 'from_financial_institution',
      attribute_value: true,
      detection_method: 'domain_lookup',
      detection_evidence: fromDomain,
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Derive from_newsletter_source attribute
 */
function deriveFromNewsletterSource(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const newsletterDomains = getNewsletterDomains(config);

  // Check domain match
  if (newsletterDomains.includes(fromDomain)) {
    return {
      attribute_name: 'from_newsletter_source',
      attribute_value: true,
      detection_method: 'domain_lookup',
      detection_evidence: fromDomain,
      confidence: 0.8,
    };
  }

  // Check List-Id header presence
  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
  if (hasListId) {
    return {
      attribute_name: 'from_newsletter_source',
      attribute_value: true,
      detection_method: 'derived',
      detection_evidence: 'List-Id header present',
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Derive from_logistics_carrier attribute
 */
function deriveFromLogisticsCarrier(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const logisticsDomains = getLogisticsDomains(config);

  if (logisticsDomains.includes(fromDomain)) {
    return {
      attribute_name: 'from_logistics_carrier',
      attribute_value: true,
      detection_method: 'domain_lookup',
      detection_evidence: fromDomain,
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Extract base domain from email address
 */
function extractBaseDomain(email: string): string {
  const domainPart = email.split('@')[1];
  if (!domainPart) return '';

  // Handle subdomains - return main domain for common patterns
  const parts = domainPart.split('.');
  if (parts.length >= 2) {
    return parts.slice(-2).join('.');
  }
  return domainPart;
}

/**
 * Get user email addresses for self_sent detection
 */
function getUserAddresses(): string[] {
  // In real implementation, this would come from user configuration
  return ['user@gmail.com', 'scotthamilton77@gmail.com'];
}

/**
 * Get financial domains for institution detection
 */
function getFinancialDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performance_cache?.financial_domains || [];
}

/**
 * Get newsletter domains for source detection
 */
function getNewsletterDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performance_cache?.newsletter_domains || [];
}

/**
 * Get logistics domains for carrier detection
 */
function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performance_cache?.logistics_domains || [];
}

/**
 * Class wrapper for AttributeDetectionStage to support legacy test patterns
 *
 * @deprecated Use executeAttributeDetection with canonical signature instead
 * NOTE: Kept for backward compatibility with existing unit tests (tests/unit/attribute-detection.test.ts)
 * Will be removed once tests migrate to canonical signature pattern.
 */
export class AttributeDetectionStage {
  async execute(email: EmailMessage, config: ProcessingConfig): Promise<AttributeDetectionResult> {
    // Create session and result using initialization utilities
    const session = createClassificationSession(config, 'sequential', 1);
    const result = createClassificationResult(email.id, session.id, 0);

    // Convert ProcessingConfig to AttributeDetectionStageConfig
    const stageConfig: AttributeDetectionStageConfig = {
      settings: config.settings,
      attributes: config.attributes,
      performance_cache: {
        financial_domains: this._getFinancialDomains(),
        newsletter_domains: this._getNewsletterDomains(),
        logistics_domains: this._getLogisticsDomains(),
      },
    };

    // Execute the canonical stage function
    executeAttributeDetection(email, session, result, stageConfig);

    // Convert result to legacy AttributeDetectionResult format
    const detectedAttributes: DetectedAttribute[] = Object.entries(result.attributeContext.detectionMetadata).map(
      ([attributeName, metadata]) => ({
        attribute_name: attributeName,
        attribute_value: true, // Default value for detected attributes
        detection_method: metadata.detectionMethod as 'pattern' | 'derived' | 'domain_lookup',
        detection_evidence: metadata.evidence || 'Detected',
        confidence: metadata.confidence,
      })
    );

    const legacyResult: AttributeDetectionResult = {
      detected_attributes: detectedAttributes,
      processing_duration_ms: Math.max(1, result.explainabilityTrace.stageTimings['attribute_detection'] || 0),
      parallel_processed: true,
      dependencies: [],
    };

    // Preserve any previous stage data from the email input
    const emailData = email as EmailMessage & Record<string, unknown>;
    if ('candidate_scores' in emailData && emailData.candidate_scores) {
      (legacyResult as Record<string, unknown>).candidate_scores = emailData.candidate_scores;
    }
    if ('stage_results' in emailData && emailData.stage_results) {
      (legacyResult as Record<string, unknown>).stage_results = emailData.stage_results;
    }

    return legacyResult;
  }

  // Mock methods for domain lookups (for testing)
  _getUserAddresses(): string[] {
    return getUserAddresses();
  }

  _getFinancialDomains(): string[] {
    return ['chase.com', 'bankofamerica.com', 'paypal.com'];
  }

  _getNewsletterDomains(): string[] {
    return ['medium.com', 'substack.com'];
  }

  _getLogisticsDomains(): string[] {
    return ['fedex.com', 'ups.com', 'usps.com'];
  }
}

/**
 * Classification Session and Result Initialization Utilities
 *
 * Provides factory functions for creating and updating classification entities
 * following the canonical signature pattern for all pipeline stages.
 *
 * CANONICAL SIGNATURE TARGET:
 * (email: EmailMessage, session: ClassificationSession, result: ClassificationResult, config: StageConfig) => StageResult
 *
 * CHARTER:
 * - ClassificationSession = "I processed a batch of emails" (batch-level metadata)
 * - ClassificationResult = "Here's everything about how I classified this one email" (per-email results)
 */

import { randomUUID, createHash } from 'crypto';
import {
  ClassificationSession,
  ClassificationResult,
  ProcessingConfig,
  ExplainabilityTrace,
  ScoreBreakdown,
  AttributeContext,
} from '../types';

/**
 * Creates a new classification session for batch email processing
 *
 * @param config - Processing configuration for the session
 * @param processingMode - Mode of processing: 'parallel' or 'sequential'
 * @param batchSize - Number of emails to process in this session
 * @returns Initialized ClassificationSession with default metrics
 */
export function createClassificationSession(
  config: ProcessingConfig,
  processingMode: 'parallel' | 'sequential' = 'parallel',
  batchSize: number = 0
): ClassificationSession {
  return {
    id: generateUuid(),
    startedAt: new Date(),
    completedAt: undefined,
    emailCount: batchSize,
    successCount: 0,
    errorCount: 0,

    processingMode,
    batchSize,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },

    configVersion: config.version.toString(),
    configSnapshot: config as object,

    errors: [],
    warnings: [],
  };
}

/**
 * Creates a new classification result for a single email
 *
 * @param emailId - Gmail message ID being classified
 * @param sessionId - ID of the classification session this email belongs to
 * @param batchPosition - Position of this email in the batch (0-indexed)
 * @returns Initialized ClassificationResult with empty traces
 */
export function createClassificationResult(
  emailId: string,
  sessionId: string,
  batchPosition: number = 0
): ClassificationResult {
  return {
    id: generateUuid(),
    emailId,
    sessionId,

    // Classification results (to be populated by pipeline stages)
    primaryCategory: '',
    secondaryCategories: [],
    confidence: 0,

    // Enhanced explainability (initialized empty, populated by stages)
    explainabilityTrace: createEmptyExplainabilityTrace(),
    scoreBreakdown: createEmptyScoreBreakdown(),
    attributeContext: createEmptyAttributeContext(),

    // Processing metadata
    processedAt: new Date(),
    processingDurationMs: 0,
    aiRoutingUsed: false,

    // Parallel processing context
    batchPosition,
    parallelStageResults: [],
  };
}

/**
 * Updates a classification result with a stage's output
 *
 * This utility function merges stage results into the ongoing ClassificationResult,
 * preserving existing data while adding new stage-specific information.
 *
 * NOTE: This is a LEGACY/BRIDGE function for stages that haven't migrated to the canonical
 * signature pattern. Canonical signature stages mutate result directly and don't need this helper.
 *
 * CANONICAL SIGNATURE PATTERN:
 * - Stages receive: (email, session, result, config)
 * - Stages mutate result.scoreBreakdown, result.explainabilityTrace, etc. directly
 * - Stages return void
 *
 * LEGACY PATTERN (this function):
 * - Stages return stageResult object
 * - This function merges stageResult into result
 *
 * @param result - The classification result to update (mutated in place)
 * @param stageResult - The result from a legacy pipeline stage
 * @param stageName - Name of the stage that produced this result
 * @returns void (mutates result in place for performance)
 *
 * @deprecated Use canonical signature pattern where stages mutate result directly
 */
export function updateResultWithStageOutput(
  result: ClassificationResult,
  stageResult: Record<string, unknown>,
  stageName: string
): void {
  // Update explainability trace with stage-specific reasoning
  // Note: ExplainabilityTrace uses specific stage arrays, not a generic 'stages' object

  // Update score breakdown if stage provides score updates
  if (stageResult.updatedScores) {
    const scores = stageResult.updatedScores as Record<string, number>;
    Object.entries(scores).forEach(([category, score]) => {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: score,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: score,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    });
  }

  // Track processing duration for this stage
  if (typeof stageResult.processingDurationMs === 'number') {
    result.processingDurationMs += stageResult.processingDurationMs;
  }

  // Update parallel stage results if applicable
  if (stageResult.parallelExecution && typeof stageResult.parallelExecution === 'object') {
    const parallelInfo = stageResult.parallelExecution as Record<string, unknown>;
    result.parallelStageResults.push({
      stageId: generateUuid(),
      stageName,
      executionTimeMs: (stageResult.processingDurationMs as number) || 0,
      parallelWithStages: (parallelInfo.parallelWith as string[]) || [],
      dependentOnStages: (parallelInfo.dependencies as string[]) || [],
      cacheHitsCount: (parallelInfo.cacheHits as number) || 0,
      errorCount: (parallelInfo.errors as number) || 0,
    });
  }

  // Update AI routing flag if this was an AI stage
  if (stageName.includes('ai_') || stageName.includes('ai-')) {
    result.aiRoutingUsed = true;
  }
}

/**
 * Finalizes a classification session after all emails are processed
 *
 * @param session - The session to finalize (mutated in place)
 * @returns void (mutates session in place for performance)
 */
export function finalizeClassificationSession(session: ClassificationSession): void {
  session.completedAt = new Date();

  // Calculate final performance metrics
  const totalDurationMs = session.completedAt.getTime() - session.startedAt.getTime();
  session.performanceMetrics.totalDurationMs = totalDurationMs;

  if (session.successCount > 0) {
    session.performanceMetrics.avgEmailDurationMs = totalDurationMs / session.successCount;
  }
}

/**
 * Increments the success count for a classification session
 *
 * @param session - The session to update (mutated in place)
 * @returns void (mutates session in place for performance)
 */
export function incrementSessionSuccess(session: ClassificationSession): void {
  session.successCount += 1;
}

/**
 * Increments the error count and records an error for a classification session
 *
 * @param session - The session to update (mutated in place)
 * @param emailId - ID of the email that failed
 * @param stage - Name of the stage where the error occurred
 * @param error - Error message or Error object
 * @param recoverable - Whether the error is recoverable
 * @returns void (mutates session in place for performance)
 */
export function incrementSessionError(
  session: ClassificationSession,
  emailId: string,
  stage: string,
  error: string | Error,
  recoverable: boolean = false
): void {
  session.errorCount += 1;
  session.errors.push({
    emailId,
    stage,
    error: error instanceof Error ? error.message : error,
    timestamp: new Date(),
    recoverable,
    retryCount: 0,
  });
}

/**
 * Adds a warning to a classification session
 *
 * @param session - The session to update (mutated in place)
 * @param emailId - ID of the email that triggered the warning
 * @param stage - Name of the stage where the warning occurred
 * @param warning - Warning message
 * @param impact - Impact level: 'low', 'medium', or 'high'
 * @returns void (mutates session in place for performance)
 */
export function addSessionWarning(
  session: ClassificationSession,
  emailId: string,
  stage: string,
  warning: string,
  impact: 'low' | 'medium' | 'high' = 'low'
): void {
  session.warnings.push({
    emailId,
    stage,
    warning,
    timestamp: new Date(),
    impact,
  });
}

// Private helper functions

/**
 * Generates a UUID v4 compatible identifier
 *
 * @returns UUID v4 string
 */
function generateUuid(): string {
  return randomUUID();
}

/**
 * Hashes a processing configuration for versioning and reproducibility
 *
 * @param config - Processing configuration to hash
 * @returns SHA-256 hash of the configuration
 *
 * @internal Currently unused but reserved for future config versioning
 */
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function hashConfig(config: ProcessingConfig): string {
  const configJson = JSON.stringify(config, Object.keys(config).sort());
  return createHash('sha256').update(configJson).digest('hex').substring(0, 16);
}

/**
 * Creates an empty explainability trace for initialization
 *
 * @returns Empty ExplainabilityTrace matching the actual type structure
 */
function createEmptyExplainabilityTrace(): ExplainabilityTrace {
  return {
    sessionId: '',
    emailId: '',
    hardAssertions: [],
    strongIndicators: [],
    ruleScoring: [],
    attributeDetection: [],
    attributeInfluence: [],
    disambiguation: [],
    multiLabelSelection: [],
    aiRouting: undefined,
    stageTimings: {},
    parallelExecutionMap: {},
    configurationRefs: {},
    finalDecisionReason: '',
    alternativeCategories: [],
  };
}

/**
 * Creates an empty score breakdown for initialization
 *
 * @returns Empty ScoreBreakdown matching the actual type structure
 */
function createEmptyScoreBreakdown(): ScoreBreakdown {
  return {
    emailId: '',
    categoryScores: {},
    stageContributions: {},
    disambiguationApplied: [],
    parallelComputationMetrics: {
      totalParallelOperations: 0,
      parallelEfficiencyScore: 0,
      bottleneckStages: [],
      peakMemoryUsageMB: 0,
      averageCpuUtilization: 0,
      concurrentOperationsPeak: 0,
      parallelizableButSequential: [],
      parallelConflicts: [],
    },
  };
}

/**
 * Creates an empty attribute context for initialization
 *
 * @returns Empty AttributeContext matching the actual type structure
 */
function createEmptyAttributeContext(): AttributeContext {
  return {
    emailId: '',
    urgency: 'low',
    domains: [],
    structuralPatterns: [],
    temporalSignals: [],
    detectionMetadata: {},
    influenceApplications: [],
    derivedAttributes: {},
    attributeRelationships: [],
  };
}

/**
 * Ensures a category score entry exists in the scoreBreakdown, initializing if needed
 *
 * This is the canonical way to initialize category scores across all pipeline stages.
 * Called by stages when they first encounter a category to ensure the score structure exists.
 *
 * @param result - Classification result to update (mutated in place)
 * @param categoryKey - Category identifier (e.g., "financial" or "financial.credit_card")
 */
export function ensureCategoryScoreInitialized(result: ClassificationResult, categoryKey: string): void {
  if (!result.scoreBreakdown.categoryScores[categoryKey]) {
    result.scoreBreakdown.categoryScores[categoryKey] = {
      baseScore: 0,
      hardAssertionBonus: 0,
      strongIndicatorScore: 0,
      ruleScore: 0,
      attributeInfluenceScore: 0,
      finalScore: 0,
      parallelComputedComponents: [],
      computationDurationMs: 0,
      cacheHits: [],
      scoreAggregationSteps: [],
      cappingApplied: false,
    };
  }
}

