        },
        required: ['urgency'],
      },
    };

    // Setup mock email message
    mockEmailMessage = {
      id: 'test_email_123',
      threadId: 'thread_456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'sender@example.com' },
          { name: 'To', value: 'user@gmail.com' },
          { name: 'Subject', value: 'Test Email' },
          { name: 'Date', value: 'Mon, 27 Sep 2025 10:00:00 +0000' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' }, // base64 encoded "Test email body"
      },
      subject: 'Test Email',
      from: { email: 'sender@example.com', name: 'Test Sender', raw: 'Test Sender <sender@example.com>' },
      to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
      date: new Date('2025-09-27T10:00:00Z'),
      bodyPlain: 'Test email body',
      isProcessed: false,
      processingPriority: 50,
    };

    // Create session and result using initialization utilities
    session = createClassificationSession(mockConfig, 'sequential', 1);
    result = createClassificationResult(mockEmailMessage.id, session.id, 0);

    // Create stage-specific config with performance cache
    stageConfig = {
      settings: mockConfig.settings,
      attributes: mockConfig.attributes,
      performance_cache: {
        financial_domains: ['chase.com', 'bankofamerica.com', 'paypal.com'],
        newsletter_domains: ['medium.com', 'substack.com'],
        logistics_domains: ['fedex.com', 'ups.com', 'usps.com'],
      },
    };
  });

  // Helper function to extract detected attributes from result for assertion
  function getDetectedAttributes(result: ClassificationResult): DetectedAttribute[] {
    return result.explainabilityTrace.attributeDetection.map((attr) => ({
      attribute_name: attr.attribute,
      attribute_value: true,
      detection_method: (attr.detectionMethod === 'direct' ? 'pattern' : 'derived') as
        | 'pattern'
        | 'derived'
        | 'domain_lookup',
      detection_evidence: attr.reason || attr.derivationLogic || 'Detected',
      confidence: attr.confidence,
    }));
  }

  describe('Pattern-based Detection', () => {
    test('should detect has_amount attribute with regex patterns', () => {
      const emailWithAmount = {
        ...mockEmailMessage,
        bodyPlain: 'Your invoice shows an amount due of $123.45 USD.',
        subject: 'Invoice Due',
      };

      // Execute the stage - it mutates result in place
      executeAttributeDetection(emailWithAmount, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_amount',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('$123.45'),
          confidence: expect.any(Number),
        })
      );
      expect(result.explainabilityTrace.stageTimings['attribute_detection']).toBeGreaterThan(0);
    });

    test('should detect has_due_date attribute with contains_any operation', () => {
      const emailWithDueDate = {
        ...mockEmailMessage,
        bodyPlain: 'Payment is due by March 15th, 2025.',
        subject: 'Payment Reminder',
      };

      executeAttributeDetection(emailWithDueDate, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_due_date',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('due by'),
        })
      );
    });

    test('should detect requires_action attribute from subject with starts_with operation', () => {
      const emailWithActionSubject = {
        ...mockEmailMessage,
        subject: 'ACTION REQUIRED: Verify your account',
        bodyPlain: 'Please verify your account information.',
      };

      executeAttributeDetection(emailWithActionSubject, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'requires_action',
          attribute_value: true,
