      };

      const result = await stage.execute(mockEmailMessage, configBadOperation);

      // Should not include the attribute with unknown operation
      const testAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'test_attr');
      expect(testAttribute).toBeUndefined();
    });

    test('should handle invalid regex patterns gracefully', async () => {
      const configInvalidRegex = {
        ...mockConfig,
        attributes: {
          ...mockConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'body',
              operation: 'regex_any',
              values: ['[invalid regex'], // Missing closing bracket
            },
          ],
        },
      };

      const result = await stage.execute(mockEmailMessage, configInvalidRegex);

      // Should handle invalid regex gracefully
      expect(result).toBeDefined();
      expect(result.detected_attributes).toBeDefined();
    });
  });

  describe('Performance Requirements', () => {
    test('should complete processing within reasonable time', async () => {
      const startTime = Date.now();

      const result = await stage.execute(mockEmailMessage, mockConfig);

      const endTime = Date.now();
      const processingTime = endTime - startTime;

      expect(processingTime).toBeLessThan(1000); // Should complete within 1 second
      expect(result.processing_duration_ms).toBeGreaterThan(0);
      expect(result.processing_duration_ms).toBeLessThan(1000);
    });

    test('should handle batch processing efficiently', async () => {
      const emails = Array(10)
        .fill(null)
        .map((_, i) => ({
          ...mockEmailMessage,
          id: `test_email_${i}`,
          bodyPlain: `Test email body with amount $${i * 10}.00`,
        }));

      const startTime = Date.now();

      const results = await Promise.all(emails.map((email) => stage.execute(email, mockConfig)));

      const endTime = Date.now();
      const totalTime = endTime - startTime;

      expect(results).toHaveLength(10);
      expect(totalTime).toBeLessThan(5000); // 10 emails in under 5 seconds

      // Each email should have detected has_amount
      results.forEach((result, _i) => {
        expect(result.detected_attributes).toContainEqual(
          expect.objectContaining({
            attribute_name: 'has_amount',
            attribute_value: true,
          })
        );
      });
    });
  });

  describe('Parallel Processing Support', () => {
    test('should support parallel processing metadata', async () => {
      const result = await stage.execute(mockEmailMessage, mockConfig);

      expect(result).toHaveProperty('parallel_processed');
      expect(result).toHaveProperty('dependencies');
      expect(Array.isArray(result.dependencies)).toBe(true);
    });

    test('should provide detection metadata for debugging', async () => {
      const emailWithAttributes = {
        ...mockEmailMessage,
        bodyPlain: 'Invoice $100 due by March 15th. Please review and reply.',
        subject: 'ACTION REQUIRED: Payment Due',
      };

      const result = await stage.execute(emailWithAttributes, mockConfig);

      // Should have multiple detected attributes
      expect(result.detected_attributes.length).toBeGreaterThan(1);

      result.detected_attributes.forEach((attr) => {
        expect(attr).toHaveProperty('attribute_name');
        expect(attr).toHaveProperty('attribute_value');
        expect(attr).toHaveProperty('detection_method');
        expect(attr).toHaveProperty('detection_evidence');
        expect(attr).toHaveProperty('confidence');
        expect(typeof attr.confidence).toBe('number');
        expect(attr.confidence).toBeGreaterThanOrEqual(0);
        expect(attr.confidence).toBeLessThanOrEqual(1);
      });
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should handle input from rule scoring stage', async () => {
      const emailWithPreviousStageData = {
        ...mockEmailMessage,
        // Simulate data from previous stages
        candidate_scores: {
          financial: 5,
          actionable: 3,
        },
        stage_results: [
          { stage: 'hard_assertions', completed: true },
          { stage: 'strong_indicators', completed: true },
          { stage: 'rule_scoring', completed: true },
        ],
      };

      const result = await stage.execute(emailWithPreviousStageData, mockConfig);

      expect(result).toBeDefined();
      expect(result.detected_attributes).toBeDefined();

      // Should preserve previous stage data
      expect(result).toHaveProperty('candidate_scores');
      expect(result).toHaveProperty('stage_results');
    });
  });
});

