/**
 * Unit Tests for Attribute Detection Stage
 *
 * TDD APPROACH: These tests are written FIRST and MUST FAIL before implementation.
 * They test all detector types, derived attributes, and edge cases.
 *
 * Tests cover:
 * - Pattern-based detection (regex_any, contains_any, starts_with)
 * - Derived attribute logic (self_sent, domain lookups)
 * - Error handling and edge cases
 * - Configuration validation
 * - Performance requirements
 */

import {
  executeAttributeDetection,
  AttributeDetectionStageConfig,
  DetectedAttribute,
} from '../../src/stages/attribute-detection';
import { EmailMessage, ProcessingConfig, ClassificationSession, ClassificationResult } from '../../src/types';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

describe('AttributeDetectionStage', () => {
  let mockConfig: ProcessingConfig;
  let stageConfig: AttributeDetectionStageConfig;
  let mockEmailMessage: EmailMessage;
  let session: ClassificationSession;
  let result: ClassificationResult;

  // Helper to recreate session and result for each test to avoid state pollution
  function resetSessionAndResult(): void {
    session = createClassificationSession(mockConfig, 'sequential', 1);
    result = createClassificationResult(mockEmailMessage.id, session.id, 0);
  }

  beforeEach(() => {
    // Setup mock configuration matching real config structure
    mockConfig = {
      version: 2,
      taxonomy_notes: 'Test config',
      settings: {
        initialization: {
          apply_hard_assertions: true,
          seed_category_scores: true,
        },
        rule_scoring: {
          use_lexical_patterns: true,
          apply_subtype_rules: true,
          bounded_aggregation: true,
        },
        attribute_processing: {
          detect_self_sent: true,
          resolve_domains: true,
          derive_context_flags: true,
        },
        attribute_influence: {
          apply_bonuses: true,
          apply_penalties: true,
          enforce_caps: true,
        },
        disambiguation: {
          pairwise_adjustments: true,
          confidence_gap_threshold: 2,
        },
        multi_label_selection: {
          max_labels: 3,
          min_secondary_confidence: 8,
          allowed_combinations: ['financial+actionable'],
        },
        ai_routing: {
          high_confidence_threshold: 15,
          ai_required_threshold: 12,
          skip_ai_conditions: ['hard_assertion'],
        },
      },
      category_signals: {},
      confidence_thresholds: {
        high_confidence: 15,
        medium_confidence: 8,
        low_confidence: 3,
        ai_classification_required: 12,
        manual_review_required: 20,
        secondary_label_min_gap: 2,
      },
      multi_label_policy: {
        max_top_level_labels: 3,
        min_confidence_for_additional: 8,
        min_delta_primary_secondary: 2,
        allow_financial_actionable_copresence: true,
      },
      domain_signal_overrides: {},
      domain_signal_resolution: {
        mode: 'runtime_resolved',
        source: 'config/domain-sources.json',
        notes: 'Domain lists resolved at runtime',
      },
      top_level_categories: {},
      attributes: {
        schema: {
          urgency: {
            type: 'enum',
            values: ['low', 'medium', 'high'],
            description: 'Relative urgency derived from language & deadlines',
          },
          requires_action: {
            type: 'boolean',
            description: 'Email requires user action',
          },
          has_amount: {
            type: 'boolean',
            description: 'Email contains monetary amounts',
          },
          has_due_date: {
            type: 'boolean',
            description: 'Email contains due dates or deadlines',
          },
          tracking_present: {
            type: 'boolean',
            description: 'Email contains tracking information',
          },
          unsubscribe_present: {
            type: 'boolean',
            description: 'Email contains unsubscribe mechanism',
          },
        },
        detectors: [
          {
            attribute: 'has_amount',
            field: 'body',
            operation: 'regex_any',
            values: ['\\$\\d+', 'USD', 'amount due'],
          },
          {
            attribute: 'has_due_date',
            field: 'body',
            operation: 'contains_any',
            values: ['due by', 'due on', 'due date', 'pay by', 'payment due'],
          },
          {
            attribute: 'requires_action',
            field: 'body',
            operation: 'contains_any',
            values: ['please review', 'action required', 'respond', 'reply', 'follow up'],
          },
          {
            attribute: 'tracking_present',
            field: 'body',
            operation: 'contains_any',
            values: ['tracking number', 'track your package'],
          },
          {
            attribute: 'unsubscribe_present',
            field: 'body',
            operation: 'contains_any',
            values: ['unsubscribe', 'manage preferences'],
          },
          {
            attribute: 'requires_action',
            field: 'subject',
            operation: 'starts_with',
            values: ['ACTION REQUIRED', 'URGENT'],
          },
        ],
        derived: {
          self_sent: {
            logic: 'from_address in user_addresses AND all_recipients in user_addresses AND NOT list_id',
            notes: 'Email sent from user to self, excluding mailing lists',
          },
          from_financial_institution: {
            logic: 'from_domain in financial_domains OR from_domain in domain_lookup.financial',
            notes: 'Email from known financial institution',
          },
          from_newsletter_source: {
            logic: 'from_domain in newsletter_domains OR list_id header present',
            notes: 'Email from newsletter or mailing list source',
          },
          from_logistics_carrier: {
            logic: 'from_domain in logistics_domains',
            notes: 'Email from shipping/logistics carrier',
          },
        },
        attribute_bonus_map: {
          has_amount: {
            financial: 2,
            commerce_logistics: 1,
          },
          requires_action: {
            actionable: 3,
            financial: 1,
          },
          tracking_present: {
            commerce_logistics: 3,
            travel: 1,
          },
        },
      },
      attribute_relevance: {
        _roles_legend: {
          CORE: 'Essential for category, strong influence',
          PRIMARY_BOOST: 'High confidence boost',
          SECONDARY_BOOST: 'Moderate confidence boost',
          DISAMBIGUATOR: 'Helps resolve close calls',
          FILTER: 'Exclusion criteria',
          STRUCTURAL: 'Email structure metadata',
          DERIVED_LINK: 'Links to other derived attributes',
          NEUTRAL: 'No direct influence',
        },
        financial: {
          category_roles: {
            has_amount: 'PRIMARY_BOOST',
            from_financial_institution: 'CORE',
            requires_action: 'SECONDARY_BOOST',
          },
        },
        actionable: {
          category_roles: {
            requires_action: 'CORE',
            has_due_date: 'PRIMARY_BOOST',
          },
        },
      },
      ai_prompts: {
        feature_extraction: {
          system_prompt: ['Extract features from email'],
          user_prompt: ['Analyze this email: {email_content}'],
        },
        final_classification: {
          system_prompt: ['Classify email into categories'],
          user_prompt: ['Classify: {email_content}'],
        },
      },
      feature_extraction_schema: {
        type: 'object',
        properties: {
          urgency: { type: 'string', enum: ['low', 'medium', 'high'] },
          topics: { type: 'array', items: { type: 'string' } },
        },
        required: ['urgency'],
      },
    };

    // Setup mock email message
    mockEmailMessage = {
      id: 'test_email_123',
      threadId: 'thread_456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'sender@example.com' },
          { name: 'To', value: 'user@gmail.com' },
          { name: 'Subject', value: 'Test Email' },
          { name: 'Date', value: 'Mon, 27 Sep 2025 10:00:00 +0000' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' }, // base64 encoded "Test email body"
      },
      subject: 'Test Email',
      from: { email: 'sender@example.com', name: 'Test Sender', raw: 'Test Sender <sender@example.com>' },
      to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
      date: new Date('2025-09-27T10:00:00Z'),
      bodyPlain: 'Test email body',
      isProcessed: false,
      processingPriority: 50,
    };

    // Create session, result, and stage-specific config
    resetSessionAndResult();

    // Create stage-specific config with performance cache
    stageConfig = {
      settings: mockConfig.settings,
      attributes: mockConfig.attributes,
      performance_cache: {
        financial_domains: ['chase.com', 'bankofamerica.com', 'paypal.com'],
        newsletter_domains: ['medium.com', 'substack.com'],
        logistics_domains: ['fedex.com', 'ups.com', 'usps.com'],
      },
    };
  });

  // Helper function to extract detected attributes from result for assertion
  function getDetectedAttributes(result: ClassificationResult): DetectedAttribute[] {
    return result.explainabilityTrace.attributeDetection.map((attr) => ({
      attribute_name: attr.attribute,
      attribute_value: true,
      detection_method: (attr.detectionMethod === 'direct' ? 'pattern' : 'derived') as
        | 'pattern'
        | 'derived'
        | 'domain_lookup',
      detection_evidence: attr.reason || attr.derivationLogic || 'Detected',
      confidence: attr.confidence,
    }));
  }

  describe('Pattern-based Detection', () => {
    test('should detect has_amount attribute with regex patterns', () => {
      resetSessionAndResult();

      const emailWithAmount = {
        ...mockEmailMessage,
        bodyPlain: 'Your invoice shows an amount due of $123.45 USD.',
        subject: 'Invoice Due',
      };

      // Execute the stage - it mutates result in place
      executeAttributeDetection(emailWithAmount, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_amount',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('$123.45'),
          confidence: expect.any(Number),
        })
      );
      expect(result.explainabilityTrace.stageTimings['attribute_detection']).toBeGreaterThan(0);
    });

    test('should detect has_due_date attribute with contains_any operation', () => {
      const emailWithDueDate = {
        ...mockEmailMessage,
        bodyPlain: 'Payment is due by March 15th, 2025.',
        subject: 'Payment Reminder',
      };

      executeAttributeDetection(emailWithDueDate, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_due_date',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('due by'),
        })
      );
    });

    test('should detect requires_action attribute from subject with starts_with operation', () => {
      const emailWithActionSubject = {
        ...mockEmailMessage,
        subject: 'ACTION REQUIRED: Verify your account',
        bodyPlain: 'Please verify your account information.',
      };

      executeAttributeDetection(emailWithActionSubject, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'requires_action',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('ACTION REQUIRED'),
        })
      );
    });

    test('should detect tracking_present attribute', () => {
      const emailWithTracking = {
        ...mockEmailMessage,
        bodyPlain: 'Your package has shipped! Track your package with number 1Z123456789.',
        subject: 'Package Shipped',
      };

      executeAttributeDetection(emailWithTracking, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'tracking_present',
          attribute_value: true,
          detection_method: 'pattern',
        })
      );
    });

    test('should detect unsubscribe_present attribute', () => {
      const emailWithUnsubscribe = {
        ...mockEmailMessage,
        bodyPlain: 'Weekly newsletter content. To unsubscribe, click here.',
        subject: 'Weekly Newsletter',
      };

      executeAttributeDetection(emailWithUnsubscribe, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'unsubscribe_present',
          attribute_value: true,
          detection_method: 'pattern',
        })
      );
    });

    test('should handle multiple pattern matches for same attribute', () => {
      const emailWithMultipleAmounts = {
        ...mockEmailMessage,
        bodyPlain: 'Invoice total: $50.00 USD. Amount due: $25.00. Previous balance was $25.00.',
        subject: 'Invoice Statement',
      };

      executeAttributeDetection(emailWithMultipleAmounts, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      const amountAttribute = detectedAttributes.find((attr) => attr.attribute_name === 'has_amount');
      expect(amountAttribute).toBeDefined();
      expect(amountAttribute?.detection_evidence).toMatch(/\$\d+/);
    });

    test('should be case insensitive for pattern matching', () => {
      const emailCaseInsensitive = {
        ...mockEmailMessage,
        bodyPlain: 'PAYMENT DUE BY MARCH 15TH',
        subject: 'URGENT PAYMENT NOTICE',
      };

      executeAttributeDetection(emailCaseInsensitive, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_due_date',
          attribute_value: true,
        })
      );
    });
  });

  describe('Derived Attributes', () => {
    test('should detect self_sent attribute for user-to-user emails', () => {
      const selfSentEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
        subject: 'Reminder to self',
        bodyPlain: 'Don\'t forget to call dentist',
      };

      executeAttributeDetection(selfSentEmail, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'self_sent',
          attribute_value: true,
          detection_method: 'derived',
          detection_evidence: expect.stringContaining('user addresses'),
        })
      );
    });

    test('should NOT detect self_sent when List-Id header present', () => {
      const mailingListEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
        payload: {
          ...mockEmailMessage.payload,
          headers: [...mockEmailMessage.payload.headers, { name: 'List-Id', value: '<newsletter.example.com>' }],
        },
      };

      executeAttributeDetection(mailingListEmail, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      const selfSentAttribute = detectedAttributes.find((attr) => attr.attribute_name === 'self_sent');
      expect(selfSentAttribute).toBeUndefined();
    });

    test('should detect from_financial_institution from domain lookup', () => {
      const financialEmail = {
        ...mockEmailMessage,
        from: { email: 'statements@chase.com', name: 'Chase Bank', raw: 'Chase Bank <statements@chase.com>' },
        subject: 'Monthly Statement',
        bodyPlain: 'Your monthly statement is ready',
      };

      executeAttributeDetection(financialEmail, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_financial_institution',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: 'chase.com',
        })
      );
    });

    test('should detect from_newsletter_source from domain or List-Id', () => {
      const newsletterEmail = {
        ...mockEmailMessage,
        from: { email: 'newsletter@medium.com', name: 'Medium', raw: 'Medium <newsletter@medium.com>' },
        payload: {
          ...mockEmailMessage.payload,
          headers: [...mockEmailMessage.payload.headers, { name: 'List-Id', value: '<digest.medium.com>' }],
        },
      };

      executeAttributeDetection(newsletterEmail, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_newsletter_source',
          attribute_value: true,
          detection_method: expect.stringMatching(/pattern|derived/),
        })
      );
    });

    test('should detect from_logistics_carrier', () => {
      const logisticsEmail = {
        ...mockEmailMessage,
        from: { email: 'tracking@fedex.com', name: 'FedEx', raw: 'FedEx <tracking@fedex.com>' },
        subject: 'Package Delivered',
        bodyPlain: 'Your package has been delivered',
      };

      executeAttributeDetection(logisticsEmail, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_logistics_carrier',
          attribute_value: true,
          detection_method: 'pattern',
        })
      );
    });
  });

  describe('Configuration Settings', () => {
    test('should respect detect_self_sent setting when disabled', () => {
      const stageConfigNoSelfSent: AttributeDetectionStageConfig = {
        ...stageConfig,
        settings: {
          ...stageConfig.settings,
          attribute_processing: {
            ...stageConfig.settings.attribute_processing,
            detect_self_sent: false,
          },
        },
      };

      const selfSentEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
      };

      executeAttributeDetection(selfSentEmail, session, result, stageConfigNoSelfSent);

      const detectedAttributes = getDetectedAttributes(result);
      const selfSentAttribute = detectedAttributes.find((attr) => attr.attribute_name === 'self_sent');
      expect(selfSentAttribute).toBeUndefined();
    });

    test('should respect resolve_domains setting when disabled', () => {
      const stageConfigNoDomains: AttributeDetectionStageConfig = {
        ...stageConfig,
        settings: {
          ...stageConfig.settings,
          attribute_processing: {
            ...stageConfig.settings.attribute_processing,
            resolve_domains: false,
          },
        },
      };

      const financialEmail = {
        ...mockEmailMessage,
        from: { email: 'statements@chase.com', name: 'Chase Bank', raw: 'Chase Bank <statements@chase.com>' },
      };

      executeAttributeDetection(financialEmail, session, result, stageConfigNoDomains);

      const detectedAttributes = getDetectedAttributes(result);
      const financialAttribute = detectedAttributes.find(
        (attr) => attr.attribute_name === 'from_financial_institution'
      );
      expect(financialAttribute).toBeUndefined();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    test('should handle missing email content gracefully', () => {
      const emailNoContent = {
        ...mockEmailMessage,
        bodyPlain: undefined,
        subject: '',
      };

      executeAttributeDetection(emailNoContent, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toEqual([]);
    });

    test('should handle malformed from address', () => {
      const emailMalformedFrom = {
        ...mockEmailMessage,
        from: { email: 'invalid-email', name: 'Invalid', raw: 'invalid-email' },
      };

      executeAttributeDetection(emailMalformedFrom, session, result, stageConfig);

      // Should not crash, should continue processing
      expect(result).toBeDefined();
      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toBeDefined();
    });

    test('should handle empty detector configuration', () => {
      const stageConfigNoDetectors: AttributeDetectionStageConfig = {
        ...stageConfig,
        attributes: {
          ...stageConfig.attributes,
          detectors: [],
        },
      };

      executeAttributeDetection(mockEmailMessage, session, result, stageConfigNoDetectors);

      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toEqual([]);
    });

    test('should handle unknown field types in detectors', () => {
      const stageConfigBadField: AttributeDetectionStageConfig = {
        ...stageConfig,
        attributes: {
          ...stageConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'unknown_field' as 'body',
              operation: 'contains_any',
              values: ['test'],
            },
          ],
        },
      };

      executeAttributeDetection(mockEmailMessage, session, result, stageConfigBadField);

      const detectedAttributes = getDetectedAttributes(result);
      // Should not include the attribute with unknown field
      const testAttribute = detectedAttributes.find((attr) => attr.attribute_name === 'test_attr');
      expect(testAttribute).toBeUndefined();
    });

    test('should handle unknown operations in detectors', () => {
      const stageConfigBadOperation: AttributeDetectionStageConfig = {
        ...stageConfig,
        attributes: {
          ...stageConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'body',
              operation: 'unknown_operation' as 'contains_any',
              values: ['test'],
            },
          ],
        },
      };

      executeAttributeDetection(mockEmailMessage, session, result, stageConfigBadOperation);

      const detectedAttributes = getDetectedAttributes(result);
      // Should not include the attribute with unknown operation
      const testAttribute = detectedAttributes.find((attr) => attr.attribute_name === 'test_attr');
      expect(testAttribute).toBeUndefined();
    });

    test('should handle invalid regex patterns gracefully', () => {
      const stageConfigInvalidRegex: AttributeDetectionStageConfig = {
        ...stageConfig,
        attributes: {
          ...stageConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'body',
              operation: 'regex_any',
              values: ['[invalid regex'], // Missing closing bracket
            },
          ],
        },
      };

      executeAttributeDetection(mockEmailMessage, session, result, stageConfigInvalidRegex);

      // Should handle invalid regex gracefully
      expect(result).toBeDefined();
      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toBeDefined();
    });
  });

  describe('Performance Requirements', () => {
    test('should complete processing within reasonable time', () => {
      const startTime = Date.now();

      executeAttributeDetection(mockEmailMessage, session, result, stageConfig);

      const endTime = Date.now();
      const processingTime = endTime - startTime;

      expect(processingTime).toBeLessThan(1000); // Should complete within 1 second
      expect(result.explainabilityTrace.stageTimings['attribute_detection']).toBeGreaterThan(0);
      expect(result.explainabilityTrace.stageTimings['attribute_detection']).toBeLessThan(1000);
    });

    test('should handle batch processing efficiently', () => {
      const emails = Array(10)
        .fill(null)
        .map((_, i) => ({
          ...mockEmailMessage,
          id: `test_email_${i}`,
          bodyPlain: `Test email body with amount $${i * 10}.00`,
        }));

      const startTime = Date.now();

      // Process all emails
      const results: ClassificationResult[] = [];
      emails.forEach((email) => {
        const batchSession = createClassificationSession(mockConfig, 'parallel', 10);
        const batchResult = createClassificationResult(email.id, batchSession.id, results.length);
        executeAttributeDetection(email, batchSession, batchResult, stageConfig);
        results.push(batchResult);
      });

      const endTime = Date.now();
      const totalTime = endTime - startTime;

      expect(results).toHaveLength(10);
      expect(totalTime).toBeLessThan(5000); // 10 emails in under 5 seconds

      // Each email should have detected has_amount
      results.forEach((batchResult) => {
        const detectedAttributes = getDetectedAttributes(batchResult);
        expect(detectedAttributes).toContainEqual(
          expect.objectContaining({
            attribute_name: 'has_amount',
            attribute_value: true,
          })
        );
      });
    });
  });

  describe('Parallel Processing Support', () => {
    test('should support parallel processing metadata', () => {
      executeAttributeDetection(mockEmailMessage, session, result, stageConfig);

      expect(result.parallelStageResults.length).toBeGreaterThan(0);
      const attrStageResult = result.parallelStageResults.find((stage) => stage.stageName === 'attribute_detection');
      expect(attrStageResult).toBeDefined();
      expect(attrStageResult?.parallelWithStages).toBeDefined();
      expect(Array.isArray(attrStageResult?.parallelWithStages)).toBe(true);
    });

    test('should provide detection metadata for debugging', () => {
      const emailWithAttributes = {
        ...mockEmailMessage,
        bodyPlain: 'Invoice $100 due by March 15th. Please review and reply.',
        subject: 'ACTION REQUIRED: Payment Due',
      };

      executeAttributeDetection(emailWithAttributes, session, result, stageConfig);

      const detectedAttributes = getDetectedAttributes(result);
      // Should have multiple detected attributes
      expect(detectedAttributes.length).toBeGreaterThan(1);

      detectedAttributes.forEach((attr) => {
        expect(attr).toHaveProperty('attribute_name');
        expect(attr).toHaveProperty('attribute_value');
        expect(attr).toHaveProperty('detection_method');
        expect(attr).toHaveProperty('detection_evidence');
        expect(attr).toHaveProperty('confidence');
        expect(typeof attr.confidence).toBe('number');
        expect(attr.confidence).toBeGreaterThanOrEqual(0);
        expect(attr.confidence).toBeLessThanOrEqual(1);
      });
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should handle input from rule scoring stage', () => {
      // Pre-populate result with data from previous stages
      result.scoreBreakdown.categoryScores['financial'] = {
        baseScore: 5,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 5,
        attributeInfluenceScore: 0,
        finalScore: 5,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
      result.scoreBreakdown.categoryScores['actionable'] = {
        baseScore: 3,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 3,
        attributeInfluenceScore: 0,
        finalScore: 3,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };

      executeAttributeDetection(mockEmailMessage, session, result, stageConfig);

      expect(result).toBeDefined();
      const detectedAttributes = getDetectedAttributes(result);
      expect(detectedAttributes).toBeDefined();

      // Should preserve previous stage data
      expect(result.scoreBreakdown.categoryScores['financial']).toBeDefined();
      expect(result.scoreBreakdown.categoryScores['actionable']).toBeDefined();
      expect(result.scoreBreakdown.categoryScores['financial'].ruleScore).toBe(5);
    });
  });
});

