   230→    confidence: number;
   231→    rationale: string;
   232→    selectedSubtypeId?: string | null;
   233→  }>,
   234→  selectedLabels: SelectedLabel[],
   235→  primaryCandidate: {
   236→    category: string;
   237→    score: number;
   238→    confidence: number;
   239→    rationale: string;
   240→    selectedSubtypeId?: string | null;
   241→  },
   242→  config: MultiLabelConfig,
   243→  thresholds: ConfidenceThresholds
   244→): void {
   245→  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
   246→    return;
   247→  }
   248→
   249→  const primaryScore = primaryCandidate.score;
   250→
   251→  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
   252→    const candidate = rankedCategories[i];
   253→    const scoreDifference = primaryScore - candidate.score;
   254→
   255→    // Check if candidate meets secondary label criteria
   256→    if (candidate.score >= config.minSecondaryConfidence && scoreDifference <= thresholds.secondaryLabelMinGap) {
   257→      // Check if combination is allowed
   258→      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
   259→        const secondaryLabel: SelectedLabel = {
   260→          category: candidate.category,
   261→          subtype: candidate.selectedSubtypeId || null,
   262→          confidence: candidate.confidence,
   263→          score: candidate.score,
   264→          isPrimary: false,
   265→          labelOrder: selectedLabels.length + 1,
   266→          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.minSecondaryConfidence})`,
   267→        };
   268→        selectedLabels.push(secondaryLabel);
   269→      }
   270→    }
   271→  }
   272→}
   273→
   274→/**
   275→ * Check if category combination is allowed based on configuration
   276→ */
   277→function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
   278→  if (primaryCategory === candidateCategory) {
   279→    return true;
   280→  }
   281→
   282→  // If strict mode is enabled and combinations are specified, only allow explicit combinations
   283→  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
   284→    const combination1 = `${primaryCategory}+${candidateCategory}`;
   285→    const combination2 = `${candidateCategory}+${primaryCategory}`;
   286→    return config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);
   287→  }
   288→
   289→  // If no combinations specified, allow all (default permissive mode)
   290→  if (config.allowedCombinations.length === 0) {
   291→    return true;
   292→  }
   293→
   294→  // If combinations are specified but not in strict mode, still check them
   295→  const combination1 = `${primaryCategory}+${candidateCategory}`;
   296→  const combination2 = `${candidateCategory}+${primaryCategory}`;
   297→  const isExplicitlyAllowed =
   298→    config.allowedCombinations.includes(combination1) || config.allowedCombinations.includes(combination2);
   299→
   300→  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   301→  return isExplicitlyAllowed || !config.strictCombinationMode;
   302→}
   303→
   304→/**
   305→ * Update category decisions based on selection results
   306→ */
   307→function updateCategoryDecisions(
   308→  candidateScores: Record<string, CategoryScore>,
   309→  selectedLabels: SelectedLabel[],
   310→  thresholds: ConfidenceThresholds
   311→): void {
   312→  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   313→
   314→  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   315→    const score = scoreData.score || 0;
   316→
   317→    if (selectedCategoryNames.has(categoryCode)) {
   318→      // Selected categories get decision based on confidence
   319→      if (score >= thresholds.highConfidence) {
   320→        scoreData.decision = 'positive';
   321→        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidence}) - finalized without AI`;
   322→      } else if (score >= thresholds.mediumConfidence) {
   323→        scoreData.decision = 'candidate';
   324→        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidence}) - may need AI validation`;
   325→      } else {
   326→        scoreData.decision = 'candidate';
   327→        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidence}) - needs AI classification`;
   328→      }
   329→    } else {
   330→      // Non-selected categories are rejected
   331→      scoreData.decision = 'rejected';
   332→      if (score < thresholds.lowConfidence) {
   333→        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidence})`;
   334→      } else {
   335→        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
   336→      }
   337→    }
   338→  }
   339→}
   340→
   341→/**
   342→ * Determine if AI classification is needed based on selected labels
   343→ */
   344→function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
   345→  if (selectedLabels.length === 0) {
   346→    return true; // No labels selected - need AI
   347→  }
   348→
   349→  // Check if primary label has high confidence (can skip AI)
   350→  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
   351→  if (primaryLabel && primaryLabel.score >= thresholds.highConfidence) {
