   455→        confidence: primaryCandidate.confidence,
   456→        score: primaryCandidate.score,
   457→        isPrimary: true,
   458→        labelOrder: 1,
   459→        selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${this.thresholds.lowConfidence})`,
   460→      };
   461→      selectedLabels.push(primaryLabel);
   462→    } else {
   463→      return this.createNoSelectionResult(startTime, rankedCategories);
   464→    }
   465→
   466→    // Select secondary labels
