/**
 * Multi-Label Selection Stage - Comprehensive Unit Tests
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests cover:
 * - Ranking algorithms for category scores
 * - Primary/secondary label selection logic
 * - Co-presence rules and allowed combinations
 * - Confidence threshold enforcement
 * - Edge cases and error scenarios
 * - AI routing decision logic
 * - Selection rationale generation
 */

import { executeMultiLabelSelection } from '../../src/stages/multi-label-selection';
import { MultiLabelConfig, ConfidenceThresholds } from '../../src/types';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';
import { EmailMessage } from '../../src/types/email-message';
import { ClassificationSession } from '../../src/types/classification-session';
import { ClassificationResult } from '../../src/types/classification-result';

describe('MultiLabelSelectionStage', () => {
  let mockConfig: MultiLabelConfig;
  let mockThresholds: ConfidenceThresholds;
  let mockEmail: EmailMessage;
  let mockSession: ClassificationSession;
  let mockResult: ClassificationResult;

  // Helper function to create score breakdown entries more concisely
  function createScoreEntry(score: number) {
    return {
      baseScore: score,
      finalScore: score,
      hardAssertionBonus: 0,
      strongIndicatorScore: 0,
      ruleScore: 0,
      attributeInfluenceScore: 0,
      parallelComputedComponents: [],
      computationDurationMs: 0,
      cacheHits: [],
      scoreAggregationSteps: [],
      cappingApplied: false,
    };
  }

  beforeEach(() => {
    // Standard configuration matching email-categorizer-config.json
    mockConfig = {
      maxLabels: 3,
      minSecondaryConfidence: 8,
      allowedCombinations: ['financial+actionable'],
    };

    mockThresholds = {
      highConfidence: 15,
      mediumConfidence: 8,
      lowConfidence: 3,
      secondaryLabelMinGap: 2,
    };

    // Create mock email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-123',
      gmailLabels: [],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
      },
      subject: 'Test Email',
      from: { email: 'test@example.com', raw: 'test@example.com' },
      to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
      date: new Date(),
      isProcessed: false,
      processingPriority: 0,
    };

    // Create mock session
    mockSession = createClassificationSession(
      {
        version: 1,
        categories: {},
        attributeRelevanceMatrix: {},
        settings: {
          confidenceThresholds: mockThresholds,
          multiLabelSelection: mockConfig,
          aiRouting: { enabled: false, providerName: '', modelName: '' },
        },
      },
      'parallel',
      1
    );

    // Create mock result
    mockResult = createClassificationResult(mockEmail.id, mockSession.id, 0);
  });

  describe('Category Ranking', () => {
    test('should rank categories by score in descending order', () => {
      // Populate result with candidate scores
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(8),
        personal: createScoreEntry(5),
        marketing: createScoreEntry(1),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      // Verify ranking by checking primary and secondary selections
      expect(mockResult.primaryCategory).toBe('financial'); // Highest score
      expect(mockResult.secondaryCategories).toContain('actionable'); // Second highest, within gap
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].selectedCategories).toContain('financial');
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].selectedCategories).toContain('actionable');
      // personal and marketing should be rejected (below threshold or gap too large)
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].rejectedCategories.map((r) => r.category)).toEqual(
        expect.arrayContaining(['personal', 'marketing'])
      );
    });

    test('should filter out categories with zero or negative scores', () => {
      // Populate result with candidate scores including zero/negative
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(0),
        personal: createScoreEntry(-2),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      // Only financial should be selected
      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toHaveLength(0);
    });

    test('should handle empty candidate scores', () => {
      // Leave result.scoreBreakdown.categoryScores empty
      mockResult.scoreBreakdown.categoryScores = {};

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      // No categories should be selected
      expect(mockResult.primaryCategory).toBe('');
      expect(mockResult.secondaryCategories).toHaveLength(0);
    });
  });

  describe('Primary Label Selection', () => {
    test('should select highest scoring category as primary if above threshold', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(11),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toContain('actionable'); // financial+actionable is allowed
      expect(mockResult.confidence).toBeGreaterThan(0);
    });

    test('should not select primary if highest score below minimum threshold', () => {
      mockResult.scoreBreakdown.categoryScores = {
        marketing: createScoreEntry(2),
        personal: createScoreEntry(1),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('');
      expect(mockResult.secondaryCategories).toHaveLength(0);
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].reason).toContain('No labels met minimum');
    });

    test('should handle single high-confidence category', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(18),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toHaveLength(0);
      expect(mockResult.confidence).toBeGreaterThan(0);
    });
  });

  describe('Secondary Label Selection', () => {
    test('should select secondary labels within score gap and above min confidence', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(11),
        personal: createScoreEntry(9),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toContain('actionable'); // gap: 1, within threshold
      expect(mockResult.secondaryCategories).not.toContain('personal'); // gap: 3, too large
    });

    test('should reject secondary labels with score gap too large', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(9), // gap: 3 > threshold of 2
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toHaveLength(0);
    });

    test('should reject secondary labels below minimum confidence', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(11),
        personal: createScoreEntry(7), // below min confidence of 8
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toEqual(['actionable']); // only actionable selected
    });

    test('should respect maximum label limit', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(15),
        actionable: createScoreEntry(14),
        personal: createScoreEntry(13),
        marketing: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      const totalLabels = 1 + mockResult.secondaryCategories.length;
      expect(totalLabels).toBeLessThanOrEqual(3); // Respects maxLabels = 3
    });
  });

  describe('Co-presence Rules and Allowed Combinations', () => {
    test('should allow explicitly configured combinations', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(11),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toContain('actionable');
    });

    test('should reject non-allowed combinations when strict mode enabled', () => {
      const restrictiveConfig = {
        ...mockConfig,
        allowedCombinations: ['financial+actionable'],
        strictCombinationMode: true,
      };

      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        personal: createScoreEntry(11), // Not allowed with financial in strict mode
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, restrictiveConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).not.toContain('personal');
    });

    test('should handle bidirectional combination matching', () => {
      mockResult.scoreBreakdown.categoryScores = {
        actionable: createScoreEntry(12), // Primary
        financial: createScoreEntry(11), // Secondary
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('actionable');
      expect(mockResult.secondaryCategories).toContain('financial');
    });

    test('should allow default combinations when none explicitly configured', () => {
      const permissiveConfig = {
        ...mockConfig,
        allowedCombinations: [],
      };

      mockResult.scoreBreakdown.categoryScores = {
        personal: createScoreEntry(12),
        marketing: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, permissiveConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('personal');
      expect(mockResult.secondaryCategories).toContain('marketing');
    });
  });

  describe('AI Routing Decision Logic', () => {
    test('should not require AI for high-confidence primary label', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(18), // >= highConfidence (15)
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.aiRoutingUsed).toBe(false);
    });

    test('should require AI when no labels selected', () => {
      mockResult.scoreBreakdown.categoryScores = {
        marketing: createScoreEntry(2), // Below threshold
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.aiRoutingUsed).toBe(true);
    });

    test('should require AI for medium confidence labels', () => {
      mockResult.scoreBreakdown.categoryScores = {
        personal: createScoreEntry(10), // Between medium (8) and high (15)
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.aiRoutingUsed).toBe(true);
    });

    test('should require AI when any label below medium confidence', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(6), // Below medium (8)
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.aiRoutingUsed).toBe(true);
    });
  });

  describe('Selection Summary Generation', () => {
    test('should generate comprehensive summary for multi-label selection', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(10),
        personal: createScoreEntry(5),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toContain('actionable');
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].rejectedCategories).toContainEqual(
        expect.objectContaining({ category: 'personal' })
      );
    });

    test('should generate summary for single label selection', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(15),
        personal: createScoreEntry(4), // Below gap threshold
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toHaveLength(0);
    });

    test('should generate summary for no selection', () => {
      mockResult.scoreBreakdown.categoryScores = {
        marketing: createScoreEntry(1), // Below threshold
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('');
      expect(mockResult.secondaryCategories).toHaveLength(0);
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].reason).toContain('No labels met minimum');
    });
  });

  describe('Category Decision Updates', () => {
    test('should mark selected categories with appropriate decisions', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(16), // High confidence
        actionable: createScoreEntry(14), // Candidate
        personal: createScoreEntry(2), // Rejected
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).toContain('actionable');
      // Verify explainability trace has rejection reason for personal
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].rejectedCategories).toContainEqual(
        expect.objectContaining({ category: 'personal' })
      );
    });

    test('should mark non-selected but adequate scores as rejected with constraint rationale', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        personal: createScoreEntry(8), // Adequate score but gap too large
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.secondaryCategories).not.toContain('personal');
      expect(mockResult.explainabilityTrace.multiLabelSelection[0].rejectedCategories).toContainEqual(
        expect.objectContaining({ category: 'personal' })
      );
    });
  });

  describe('Edge Cases and Error Handling', () => {
    test('should handle missing score data gracefully', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: {
          baseScore: undefined as unknown as number,
          finalScore: undefined as unknown as number,
          hardAssertionBonus: 0,
          strongIndicatorScore: 0,
          ruleScore: 0,
          attributeInfluenceScore: 0,
          parallelComputedComponents: [],
          computationDurationMs: 0,
          cacheHits: [],
          scoreAggregationSteps: [],
          cappingApplied: false,
        },
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('');
      expect(mockResult.secondaryCategories).toHaveLength(0);
    });

    test('should handle missing confidence data gracefully', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
      expect(mockResult.confidence).toBeGreaterThanOrEqual(0);
    });

    test('should handle identical scores with stable ordering', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(10),
        actionable: createScoreEntry(10),
        personal: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      // Should have stable, deterministic ordering (alphabetical by category name)
      expect(mockResult.primaryCategory).toBeTruthy();
      const totalLabels = 1 + mockResult.secondaryCategories.length;
      expect(totalLabels).toBeLessThanOrEqual(3);
    });

    test('should handle configuration edge cases', () => {
      const edgeCaseConfig = {
        maxLabels: 0, // Invalid
        minSecondaryConfidence: -1, // Invalid
        allowedCombinations: [],
      };

      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      expect(() => {
        executeMultiLabelSelection(mockEmail, mockSession, mockResult, edgeCaseConfig as MultiLabelConfig, mockThresholds);
      }).toThrow('Invalid configuration');
    });

    test('should validate threshold consistency', () => {
      const invalidThresholds = {
        highConfidence: 5,
        mediumConfidence: 10, // Medium > High - invalid
        lowConfidence: 15, // Low > Medium > High - invalid
        secondaryLabelMinGap: -1, // Negative gap - invalid
      };

      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      expect(() => {
        executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, invalidThresholds as ConfidenceThresholds);
      }).toThrow('Invalid threshold configuration');
    });
  });

  describe('Subtype Handling', () => {
    test('should preserve subtype information in selected labels', () => {
      // Note: Current canonical signature doesn't use selectedSubtypeId from CategoryScore
      // This test verifies the function doesn't error with subtype data
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
    });

    test('should handle missing subtype gracefully', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
    });
  });

  describe('Performance and Efficiency', () => {
    test('should handle large number of categories efficiently', () => {
      const startTime = Date.now();

      // Generate 100 categories
      const categoryScores: Record<string, ReturnType<typeof createScoreEntry>> = {};
      for (let i = 0; i < 100; i++) {
        categoryScores[`category_${i}`] = createScoreEntry(Math.floor(Math.random() * 20));
      }
      mockResult.scoreBreakdown.categoryScores = categoryScores;

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      const duration = Date.now() - startTime;

      expect(duration).toBeLessThan(100); // Should complete in <100ms
      const totalLabels = mockResult.primaryCategory ? 1 + mockResult.secondaryCategories.length : 0;
      expect(totalLabels).toBeLessThanOrEqual(3); // Respects max labels
    });

    test('should maintain stable sorting for reproducible results', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);
      const primary1 = mockResult.primaryCategory;
      const secondary1 = [...mockResult.secondaryCategories];

      // Reset and run again
      mockResult = createClassificationResult(mockEmail.id, mockSession.id, 0);
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);
      const primary2 = mockResult.primaryCategory;
      const secondary2 = [...mockResult.secondaryCategories];

      expect(primary1).toBe(primary2);
      expect(secondary1).toEqual(secondary2);
    });
  });
});

