          mockSession,
          mockResult,
          edgeCaseConfig as MultiLabelConfig,
          mockThresholds
        );
      }).toThrow('Invalid configuration');
    });

    test('should validate threshold consistency', () => {
      const invalidThresholds = {
        highConfidence: 5,
        mediumConfidence: 10, // Medium > High - invalid
        lowConfidence: 15, // Low > Medium > High - invalid
        secondaryLabelMinGap: -1, // Negative gap - invalid
      };

      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      expect(() => {
        executeMultiLabelSelection(
          mockEmail,
          mockSession,
          mockResult,
          mockConfig,
          invalidThresholds as ConfidenceThresholds
        );
      }).toThrow('Invalid threshold configuration');
    });
  });

  describe('Subtype Handling', () => {
    test('should preserve subtype information in selected labels', () => {
      // Note: Current canonical signature doesn't use selectedSubtypeId from CategoryScore
      // This test verifies the function doesn't error with subtype data
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
    });

    test('should handle missing subtype gracefully', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      expect(mockResult.primaryCategory).toBe('financial');
    });
  });

  describe('Performance and Efficiency', () => {
    test('should handle large number of categories efficiently', () => {
      const startTime = Date.now();

      // Generate 100 categories
      const categoryScores: Record<string, ReturnType<typeof createScoreEntry>> = {};
      for (let i = 0; i < 100; i++) {
        categoryScores[`category_${i}`] = createScoreEntry(Math.floor(Math.random() * 20));
      }
      mockResult.scoreBreakdown.categoryScores = categoryScores;

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);

      const duration = Date.now() - startTime;

      expect(duration).toBeLessThan(100); // Should complete in <100ms
      const totalLabels = mockResult.primaryCategory ? 1 + mockResult.secondaryCategories.length : 0;
      expect(totalLabels).toBeLessThanOrEqual(3); // Respects max labels
    });

    test('should maintain stable sorting for reproducible results', () => {
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);
      const primary1 = mockResult.primaryCategory;
      const secondary1 = [...mockResult.secondaryCategories];

      // Reset and run again
      mockResult = createClassificationResult(mockEmail.id, mockSession.id, 0);
      mockResult.scoreBreakdown.categoryScores = {
        financial: createScoreEntry(12),
        actionable: createScoreEntry(10),
      };

      executeMultiLabelSelection(mockEmail, mockSession, mockResult, mockConfig, mockThresholds);
      const primary2 = mockResult.primaryCategory;
      const secondary2 = [...mockResult.secondaryCategories];

      expect(primary1).toBe(primary2);
      expect(secondary1).toEqual(secondary2);
    });
  });
});

