/**
 * Class wrapper for AttributeDetectionStage to support legacy test patterns
 *
 * @deprecated Use executeAttributeDetection with canonical signature instead
 * NOTE: Kept for backward compatibility with existing unit tests (tests/unit/attribute-detection.test.ts)
 * Will be removed once tests migrate to canonical signature pattern.
 */
export class AttributeDetectionStage {
  async execute(email: EmailMessage, config: ProcessingConfig): Promise<AttributeDetectionResult> {
    // Create session and result using initialization utilities
    const session = createClassificationSession(config, 'sequential', 1);
    const result = createClassificationResult(email.id, session.id, 0);

    // Convert ProcessingConfig to AttributeDetectionStageConfig
    const stageConfig: AttributeDetectionStageConfig = {
      settings: config.settings,
      attributes: config.attributes,
      performance_cache: {
        financial_domains: this._getFinancialDomains(),
        newsletter_domains: this._getNewsletterDomains(),
        logistics_domains: this._getLogisticsDomains(),
      },
    };

    // Execute the canonical stage function
    executeAttributeDetection(email, session, result, stageConfig);

    // Convert result to legacy AttributeDetectionResult format
    const detectedAttributes: DetectedAttribute[] = Object.entries(result.attributeContext.detectionMetadata).map(
      ([attributeName, metadata]) => ({
        attribute_name: attributeName,
        attribute_value: true, // Default value for detected attributes
        detection_method: metadata.detectionMethod as 'pattern' | 'derived' | 'domain_lookup',
        detection_evidence: metadata.evidence || 'Detected',
        confidence: metadata.confidence,
      })
    );

    const legacyResult: AttributeDetectionResult = {
      detected_attributes: detectedAttributes,
      processing_duration_ms: Math.max(1, result.explainabilityTrace.stageTimings['attribute_detection'] || 0),
      parallel_processed: true,
      dependencies: [],
    };

    // Preserve any previous stage data from the email input
    const emailData = email as EmailMessage & Record<string, unknown>;
    if ('candidate_scores' in emailData && emailData.candidate_scores) {
      (legacyResult as Record<string, unknown>).candidate_scores = emailData.candidate_scores;
    }
    if ('stage_results' in emailData && emailData.stage_results) {
      (legacyResult as Record<string, unknown>).stage_results = emailData.stage_results;
    }

    return legacyResult;
  }

  // Mock methods for domain lookups (for testing)
  _getUserAddresses(): string[] {
    return getUserAddresses();
  }

  _getFinancialDomains(): string[] {
    return ['chase.com', 'bankofamerica.com', 'paypal.com'];
  }

  _getNewsletterDomains(): string[] {
    return ['medium.com', 'substack.com'];
  }

  _getLogisticsDomains(): string[] {
    return ['fedex.com', 'ups.com', 'usps.com'];
  }
}

