/**
 * Classification Pipeline Orchestrator (MINIMAL MVP for Phase 3.5.2)
 *
 * This is a MINIMAL implementation for T036i establishing the basic orchestration pattern.
 * Full integration with all 9 stages and proper config mapping will be completed in Phase 3.6 (T040-T041).
 *
 * Current Implementation:
 * - Demonstrates sequential stage execution pattern
 * - Establishes context propagation architecture
 * - Provides basic error handling and performance tracking
 * - Returns classification results in expected format
 *
 * Phase 3.6 Enhancements:
 * - Complete config mapping from ProcessingConfig to individual stage configs
 * - Full 9-stage pipeline with AI routing, feature extraction, and final decision
 * - Advanced error handling with partial failure recovery
 * - Batch processing optimization
 */

import { EmailMessage } from '../types/email-message';
import { ProcessingConfig } from '../types/category-configuration';
import { ClassificationResult } from '../types/classification-result';

// Validation utilities
import { validateEmailInput, validateConfigInput } from '../utils/validation';

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Classification Pipeline orchestrator
 *
 * Manages sequential execution of classification stages with proper context
 * propagation, error handling, and performance tracking.
 */
export class ClassificationPipeline {
  private readonly config: ProcessingConfig;

  /**
   * Initialize classification pipeline with validated configuration
   *
   * @param config - Complete processing configuration for all stages
   * @throws {Error} If configuration validation fails
   */
  constructor(config: ProcessingConfig) {
    // Validate configuration
    validateConfigInput(config);

    // Validate confidence thresholds specifically
    const { confidence_thresholds } = config;
    if (
      !confidence_thresholds ||
      confidence_thresholds.high_confidence < 0 ||
      confidence_thresholds.medium_confidence < 0 ||
      confidence_thresholds.low_confidence < 0 ||
      confidence_thresholds.secondary_label_min_gap < 0
    ) {
      throw new Error('Invalid confidence thresholds: all values must be non-negative');
    }

    // Store config for Phase 3.6 when full stage integration happens
    this.config = config;
  }

  /**
   * Get configuration (for testing and future stage integration)
   */
  getConfig(): ProcessingConfig {
    return this.config;
  }

  /**
   * Execute classification pipeline on single email (MINIMAL MVP)
   *
   * This minimal implementation:
   * 1. Validates inputs
   * 2. Returns a basic classification result
   * 3. Demonstrates the expected interface
   *
   * Full stage-by-stage execution will be implemented in Phase 3.6.
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email);

      // MINIMAL MVP: Return placeholder result
      // Full pipeline execution (stages 1-9) will be implemented in Phase 3.6
      const pipelineEndTime = Date.now();
      const totalDuration = pipelineEndTime - pipelineStartTime;

      return {
        id: `classification-${email.id}-${Date.now()}`,
        emailId: email.id,
        sessionId: 'mvp-session',
        primaryCategory: '',
        secondaryCategories: [],
        confidence: 0,
        explainabilityTrace: {
          stages: [],
          decisionPath: [],
          totalProcessingTimeMs: totalDuration,
        },
        scoreBreakdown: {
          hardAssertions: {},
          strongIndicators: {},
          ruleScoring: {},
          attributeInfluence: {},
          disambiguation: {},
          finalScores: {},
        },
        attributeContext: {
          detectedAttributes: {},
          attributeInfluences: {},
        },
        processedAt: new Date(),
        processingDurationMs: totalDuration,
        aiRoutingUsed: false,
        batchPosition: 0,
        parallelStageResults: [],
      };
    } catch (error) {
      // Capture error with processing time
      const pipelineEndTime = Date.now();
      throw new Error(
        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Process multiple emails sequentially
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    for (const email of emails) {
      const startTime = Date.now();
      try {
        const result = await this.classify(email);
        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    return results;
  }
}

