     2→ * Audit Trail Generation Stage
     3→ *
     4→ * Stage 9+ (post-processing) of the EmailCategorizer pipeline. Generates complete
     5→ * explainability traces consolidating results from all 9 classification pipeline stages.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Aggregating results from all pipeline stages into a unified explainability trace
     9→ * - Tracking performance metadata (stage timings, parallel execution maps)
    10→ * - Collecting configuration references used throughout the pipeline
    11→ * - Generating final decision rationale summarizing the complete classification process
    12→ * - Producing database-compatible JSON format for persistence
    13→ *
    14→ * Reference: PrepareRuleScoringPersistenceNode.js and other Prepare*PersistenceNode.js files
    15→ * Document: SCORING_LOGIC.md "Explainability Trace Structure" section
    16→ */
    17→
    18→import { z } from 'zod';
    19→import { EmailMessage, ClassificationSession } from '../types';
    20→import {
    21→  ExplainabilityTrace,
    22→  HardAssertionResult,
    23→  StrongIndicatorResult,
    24→  RuleEvaluationResult,
    25→  AttributeDetectionResult,
    26→  AttributeInfluenceResult,
    27→  DisambiguationResult,
    28→  MultiLabelResult as ExplainMultiLabelResult,
    29→  AIRoutingResult,
    30→} from '../types/explainability-trace';
    31→import { MultiLabelSelectionResult } from './types';
    32→import { FinalDecisionResult } from './final-decision';
    33→import { validateEmailInput, validateSessionInput } from '../utils/validation';
    34→
    35→// Zod schema for audit trail configuration
    36→export const AuditTrailConfigSchema = z.object({
    37→  includePerformanceMetrics: z.boolean().default(true),
    38→  includeConfigurationRefs: z.boolean().default(true),
    39→  serializationFormat: z.enum(['json', 'jsonb']).default('json'),
    40→});
    41→
    42→// Configuration interface for audit trail generation
    43→export interface AuditTrailConfig {
    44→  includePerformanceMetrics: boolean;
    45→  includeConfigurationRefs: boolean;
    46→  serializationFormat: 'json' | 'jsonb';
    47→}
    48→
    49→// Pipeline results interface aggregating all stage outputs
    50→export interface PipelineResults {
    51→  hardAssertions: HardAssertionsStageResult;
    52→  strongIndicators: StrongIndicatorsStageResult;
    53→  ruleScoring: RuleScoringStageResult;
    54→  attributeDetection: AttributeDetectionStageResult;
    55→  attributeInfluence: AttributeInfluenceStageResult;
    56→  disambiguation: DisambiguationStageResult;
    57→  multiLabelSelection: MultiLabelSelectionResult;
    58→  aiRouting: AIRoutingStageResult;
    59→  finalDecision: FinalDecisionResult;
    60→}
    61→
    62→// Individual stage result interfaces (for audit trail aggregation purposes)
    63→export interface HardAssertionsStageResult {
    64→  appliedAssertions: HardAssertionResult[];
    65→  processingDurationMs: number;
    66→}
    67→
    68→export interface StrongIndicatorsStageResult {
    69→  appliedIndicators: StrongIndicatorResult[];
    70→  processingDurationMs: number;
    71→}
    72→
    73→export interface RuleScoringStageResult {
    74→  categoryScores: Record<string, number>;
    75→  subtypeScores: Record<string, Record<string, number>>;
    76→  ruleMatches?: RuleEvaluationResult[];
    77→  processingDurationMs: number;
    78→}
    79→
    80→export interface AttributeDetectionStageResult {
    81→  detectedAttributes: AttributeDetectionResult[];
    82→  processingDurationMs: number;
    83→}
    84→
    85→export interface AttributeInfluenceStageResult {
    86→  appliedInfluences: AttributeInfluenceResult[];
    87→  processingDurationMs: number;
    88→}
    89→
    90→export interface DisambiguationStageResult {
    91→  adjustments: DisambiguationResult[];
    92→  processingDurationMs: number;
    93→}
    94→
    95→export interface AIRoutingStageResult {
    96→  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
    97→  highConfidenceThreshold: number;
    98→  aiRequiredThreshold: number;
    99→  skipConditions: string[];
   100→  aiResponse?: {
   101→    extractedFeatures?: object;
   102→    suggestedCategories?: string[];
   103→    confidence: number;
   104→    reasoning: string;
   105→  };
   106→  reason: string;
   107→  processingDurationMs: number;
   108→}
   109→
   110→// Complete audit trail result
   111→export interface AuditTrailResult {
   112→  sessionId: string;
   113→  emailId: string;
   114→  explainabilityTrace: ExplainabilityTrace;
   115→  processingDurationMs: number;
   116→}
   117→
   118→/**
   119→ * Generate Audit Trail
   120→ *
   121→ * Consolidates results from all 9 pipeline stages into a complete explainability trace
   122→ * for database persistence and debugging purposes.
   123→ *
   124→ * @param email - Email message being classified
   125→ * @param session - Classification session metadata
   126→ * @param pipelineResults - Results from all 9 pipeline stages
   127→ * @param config - Audit trail configuration
   128→ * @returns Complete audit trail with explainability trace
   129→ */
   130→export function generateAuditTrail(
   131→  email: EmailMessage,
   132→  session: ClassificationSession,
   133→  pipelineResults: PipelineResults,
   134→  config: AuditTrailConfig
   135→): AuditTrailResult {
   136→  const startTime = Date.now();
   137→
   138→  // Validate inputs
   139→  validateInputs(email, session, pipelineResults);
   140→
   141→  // Extract session and email IDs (support both id and legacy _id formats)
   142→  const sessionId = session.id || ((session as unknown as Record<string, unknown>).session_id as string);
   143→  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmail_id as string);
   144→
   145→  // Aggregate stage timings
   146→  const stageTimings = aggregateStageTimings(pipelineResults);
   147→
   148→  // Build parallel execution map
   149→  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);
   150→
   151→  // Collect configuration references
   152→  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};
   153→
   154→  // Generate final decision reason
   155→  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);
   156→
   157→  // Extract alternative categories
   158→  const alternativeCategories = extractAlternativeCategories(pipelineResults);
   159→
   160→  // Convert multi-label selection results to explainability format
   161→  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);
   162→
   163→  // Build AI routing result
   164→  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);
   165→
   166→  // Construct complete explainability trace
   167→  const explainabilityTrace: ExplainabilityTrace = {
   168→    sessionId,
   169→    emailId,
   170→    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
   171→    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
   172→    ruleScoring: pipelineResults.ruleScoring.ruleMatches || [],
   173→    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
   174→    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
   175→    disambiguation: pipelineResults.disambiguation.adjustments,
   176→    multiLabelSelection: multiLabelResults,
   177→    aiRouting: aiRoutingResult,
   178→    stageTimings,
   179→    parallelExecutionMap,
   180→    configurationRefs,
   181→    finalDecisionReason,
   182→    alternativeCategories,
   183→  };
   184→
   185→  return {
   186→    sessionId,
   187→    emailId,
   188→    explainabilityTrace,
   189→    processingDurationMs: Date.now() - startTime,
   190→  };
   191→}
   192→
   193→/**
   194→ * Validate input parameters
   195→ */
   196→function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
   197→  validateEmailInput(email);
   198→  validateSessionInput(session);
   199→
   200→  if (!pipelineResults || typeof pipelineResults !== 'object') {
   201→    throw new Error('Invalid pipeline results: object required');
   202→  }
   203→
   204→  // Validate required stages
   205→  const requiredStages = [
   206→    'hardAssertions',
   207→    'strongIndicators',
   208→    'ruleScoring',
   209→    'attributeDetection',
   210→    'attributeInfluence',
   211→    'disambiguation',
   212→    'multiLabelSelection',
   213→    'aiRouting',
   214→    'finalDecision',
   215→  ];
   216→
   217→  for (const stage of requiredStages) {
   218→    if (!pipelineResults[stage as keyof PipelineResults]) {
   219→      throw new Error(`Missing required pipeline stage: ${stage}`);
   220→    }
   221→  }
   222→}
   223→
   224→/**
   225→ * Aggregate stage timings from all pipeline stages
   226→ */
   227→function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
   228→  return {
   229→    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
   230→    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
   231→    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
   232→    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
   233→    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
   234→    disambiguation: pipelineResults.disambiguation.processingDurationMs,
   235→    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
   236→    aiRouting: pipelineResults.aiRouting.processingDurationMs,
   237→    finalDecision: pipelineResults.finalDecision.processingDurationMs,
   238→  };
   239→}
   240→
   241→/**
   242→ * Build parallel execution map tracking which stages/attributes ran concurrently
   243→ */
   244→function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
   245→  const parallelMap: Record<string, string[]> = {};
   246→
   247→  // Track parallel-processed attributes from attribute detection stage
   248→  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
   249→    .filter((attr) => attr.parallelProcessed)
   250→    .map((attr) => attr.attribute);
   251→
   252→  if (parallelAttributes.length > 0) {
   253→    parallelMap.attributeDetection = parallelAttributes;
   254→  }
   255→
   256→  return parallelMap;
   257→}
   258→
   259→/**
   260→ * Collect configuration references used throughout the pipeline
   261→ */
   262→function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
   263→  const refs: Record<string, string> = {};
   264→
   265→  // Hard assertions config
   266→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   267→    refs.hardAssertions = 'config.processing_config.category_signals.*.hard_assertions';
   268→  }
   269→
   270→  // Strong indicators config
   271→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   272→    refs.strongIndicators = 'config.processing_config.category_signals.*.strong_indicators';
   273→  }
   274→
   275→  // Rule scoring config
   276→  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
   277→    refs.ruleScoring = 'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
   278→  }
   279→
   280→  // Attribute detection config
   281→  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
   282→    refs.attributeDetection = 'config.processing_config.attributes.detectors';
   283→  }
   284→
   285→  // Attribute influence config
   286→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   287→    refs.attributeInfluence = 'config.processing_config.attribute_relevance';
   288→  }
   289→
   290→  // Disambiguation config
   291→  if (pipelineResults.disambiguation.adjustments.length > 0) {
   292→    refs.disambiguation = 'config.processing_config.settings.disambiguation.confidence_gap_threshold';
   293→  }
   294→
   295→  // Multi-label selection config
   296→  refs.multiLabelSelection = 'config.processing_config.multi_label_policy';
   297→
   298→  // AI routing config
   299→  refs.aiRouting = 'config.processing_config.confidence_thresholds';
   300→
   301→  // Final decision config
   302→  refs.finalDecision = 'config.processing_config.settings.archive_threshold';
   303→
   304→  return refs;
   305→}
   306→
   307→/**
   308→ * Generate final decision reason summarizing the complete classification pipeline
   309→ */
   310→function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
   311→  const reasons: string[] = [];
   312→
   313→  // Check for hard assertions (highest priority)
   314→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   315→    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
   316→    reasons.push(`Hard assertion matched for categories: ${[...new Set(categories)].join(', ')}`);
   317→  }
   318→
   319→  // Check for strong indicators
   320→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   321→    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
   322→    reasons.push(`Strong indicators detected for: ${[...new Set(categories)].join(', ')}`);
   323→  }
   324→
   325→  // Include rule scoring results
   326→  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
   327→    .sort((a, b) => b[1] - a[1])
   328→    .slice(0, 3);
   329→
   330→  if (topCategories.length > 0) {
   331→    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
   332→    reasons.push(`Top rule-based scores: ${categoryScores}`);
   333→  }
   334→
   335→  // Include attribute influences
   336→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   337→    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
   338→    reasons.push(`${attributeCount} attribute bonuses applied`);
   339→  }
   340→
   341→  // Include AI routing decision
   342→  if (pipelineResults.aiRouting.routingDecision !== 'skip_ai') {
   343→    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
   344→  }
   345→
   346→  // Include final decision
   347→  const finalLabels = pipelineResults.finalDecision.assignedLabels;
   348→  reasons.push(`Final assignment: primary=${finalLabels.primary}, secondary=[${finalLabels.secondary.join(', ')}]`);
   349→
   350→  if (pipelineResults.finalDecision.determinedActions.length > 0) {
   351→    reasons.push(`Actions: ${pipelineResults.finalDecision.determinedActions.join(', ')}`);
   352→  }
   353→
   354→  return reasons.join('; ');
   355→}
   356→
   357→/**
   358→ * Extract alternative categories that were not selected
   359→ */
   360→function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
   361→  category: string;
   362→  score: number;
   363→  eliminationReason: string;
   364→}> {
   365→  const alternatives: Array<{
   366→    category: string;
   367→    score: number;
   368→    eliminationReason: string;
   369→  }> = [];
   370→
   371→  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
   372→  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
   373→  const selectedCategories = [finalPrimary, ...finalSecondary];
   374→
   375→  // Get all categories from rule scoring
   376→  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);
   377→
   378→  for (const [category, score] of allCategories) {
   379→    if (!selectedCategories.includes(category)) {
   380→      let eliminationReason = 'Score below selection threshold';
   381→
   382→      // Check if filtered by multi-label selection
   383→      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
   384→      const wasFiltered = filteredLabels.find((f) => f.category === category);
   385→      if (wasFiltered) {
   386→        eliminationReason = wasFiltered.filterReason;
   387→      }
   388→
   389→      alternatives.push({
   390→        category,
   391→        score,
   392→        eliminationReason,
   393→      });
   394→    }
   395→  }
   396→
   397→  // Sort by score descending
   398→  alternatives.sort((a, b) => b.score - a.score);
   399→
   400→  return alternatives;
   401→}
   402→
   403→/**
   404→ * Convert multi-label selection results to explainability format
   405→ */
   406→function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
   407→  return multiLabelResult.selectedLabels.map((label) => ({
   408→    selectedCategories: [label.category],
   409→    rejectedCategories: [],
   410→    coPresenceRulesApplied: [],
   411→    maxLabelsLimit: 1,
   412→    minSecondaryConfidence: 0,
   413→    reason: label.selectionRationale,
   414→  }));
   415→}
   416→
   417→/**
   418→ * Build AI routing result for explainability trace
   419→ */
   420→function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
   421→  // AI routing is optional - only include if AI was actually used
   422→  if (aiRoutingResult.routingDecision === 'skip_ai' && !aiRoutingResult.aiResponse) {
   423→    return {
   424→      routingDecision: aiRoutingResult.routingDecision,
   425→      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   426→      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   427→      skipConditions: aiRoutingResult.skipConditions,
   428→      reason: aiRoutingResult.reason,
   429→    };
   430→  }
   431→
   432→  return {
   433→    routingDecision: aiRoutingResult.routingDecision,
   434→    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   435→    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   436→    skipConditions: aiRoutingResult.skipConditions,
   437→    aiResponse: aiRoutingResult.aiResponse,
   438→    reason: aiRoutingResult.reason,
   439→  };
   440→}
   441→

