switch (rule.operation) {
  case 'contains_any':
    pattern = new RegExp(
      rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '',
      'i'
    );
    break;
  case 'starts_with':
    pattern = new RegExp(
      '^(' +
        (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '') +
        ')',
      'i'
    );
    break;
  case 'ends_with':
    pattern = new RegExp(
      '(' +
        (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '') +
        ')$',
      'i'
    );
    break;
  case 'regex_any':
    pattern = new RegExp(rule.values?.join('|') || '', 'i');
    break;
  default:
    continue; // Skip unknown operations
}

