toolUseResult.originalFile:
/**
 * Email Utilities
 *
 * Business-logic-agnostic utility functions for email processing.
 * These functions are reused across multiple classification stages.
 */

/**
 * Extract domain from email address
 * @param email Email address (e.g., "user@example.com")
 * @returns Domain portion (e.g., "example.com") in lowercase
 */
export function extractDomainFromEmail(email: string): string {
  const atIndex = email.lastIndexOf('@');
  if (atIndex === -1) {
    return email; // Invalid email, return as-is
  }
  return email.substring(atIndex + 1).toLowerCase();
}

/**
 * Check if email domain matches configured domain
 * Supports exact matches and subdomain matching
 *
 * @param emailDomain Domain from email address (should be lowercase)
 * @param configDomain Domain from configuration
 * @returns True if domains match
 *
 * @example
 * domainMatches("chase.com", "chase.com") // true - exact match
 * domainMatches("noreply.chase.com", "chase.com") // true - subdomain match
 * domainMatches("chase.net", "chase.com") // false - different domain
 */
export function domainMatches(emailDomain: string, configDomain: string): boolean {
  const emailDomainLower = emailDomain.toLowerCase();
  const configDomainLower = configDomain.toLowerCase();

  // Exact match
  if (emailDomainLower === configDomainLower) {
    return true;
  }

  // Subdomain match (e.g., noreply.chase.com matches chase.com)
  if (emailDomainLower.endsWith('.' + configDomainLower)) {
    return true;
  }

  return false;
}

/**
 * Extract plain text from HTML content
 * Removes HTML tags, scripts, styles, and normalizes whitespace.
 * For production use, consider using a proper HTML parser like jsdom or cheerio.
 *
 * @param html HTML content
 * @returns Plain text content with normalized whitespace
 *
 * @example
 * extractTextFromHtml("<p>Hello <b>world</b>!</p>") // "Hello world!"
 * extractTextFromHtml("<div>Line 1<br>Line 2</div>") // "Line 1 Line 2"
 */
export function extractTextFromHtml(html: string): string {
  return html
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, ' ') // Remove script tags and content (add space)
    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, ' ') // Remove style tags and content (add space)
    .replace(/<[^>]*>/g, ' ') // Remove all HTML tags (add space)
    .replace(/&nbsp;/g, ' ') // Replace non-breaking spaces with regular spaces
    .replace(/&lt;/g, '<') // Replace common HTML entities
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&[^;]+;/g, '') // Remove any remaining HTML entities
    .replace(/\s+/g, ' ') // Normalize all whitespace to single spaces
    .trim();
}

/**
 * Extract body text from email message
 * Prefers plain text body, falls back to extracting text from HTML body.
 * This function standardizes body text extraction across all classification stages.
 *
 * @param email Email message object with bodyPlain and/or bodyHtml fields
 * @returns Extracted body text (plain or from HTML), empty string if no body content
 *
 * @example
 * // With plain text
 * extractEmailBodyText({ bodyPlain: "Hello", bodyHtml: "<p>World</p>" }) // "Hello"
 *
 * // HTML only
 * extractEmailBodyText({ bodyHtml: "<p>Hello world</p>" }) // "Hello world"
 *
 * // No body content
 * extractEmailBodyText({}) // ""
 */
export function extractEmailBodyText(email: { bodyPlain?: string; bodyHtml?: string }): string {
  // Prefer plain text body
  if (email.bodyPlain) {
    return email.bodyPlain.trim();
  }

  // Fall back to extracting text from HTML
  if (email.bodyHtml) {
    return extractTextFromHtml(email.bodyHtml);
  }

  // No body content available
  return '';
}

/**
 * Find matching domain in domain lookup based on confidence level
 * Used by both hard assertions and strong indicators stages
 *
 * @param emailDomain Domain from email address
 * @param domainGroup Domain group configuration with confidence levels
 * @param confidence Confidence level to check ('high' or 'medium')
 * @returns Matching domain object or null if no match found
 */
export function findMatchingDomain(
  emailDomain: string,
  domainGroup: {
    high_confidence: Array<{ domain: string; type?: string }>;
    medium_confidence: Array<{ domain: string; type?: string }>;
    low_confidence: Array<{ domain: string; type?: string }>;
  },
  confidence: 'high' | 'medium'
): { domain: string; type?: string } | null {
  // Check appropriate confidence level
  const domainsToCheck = confidence === 'high' ? domainGroup.high_confidence : domainGroup.medium_confidence;

  return domainsToCheck.find((d) => domainMatches(emailDomain, d.domain)) || null;
}

/**
 * Check if text contains any of the specified keywords (case-insensitive)
 *
 * @param text Text to search in
 * @param keywords Array of keywords to search for
 * @returns Array of matched keywords (in original case), empty if no matches
 *
 * @example
 * findMatchingKeywords("Invoice #123 due", ["invoice", "receipt"]) // ["invoice"]
 * findMatchingKeywords("Hello world", ["payment", "bill"]) // []
 */
export function findMatchingKeywords(text: string, keywords: string[]): string[] {
  if (!text || !keywords || keywords.length === 0) {
    return [];
  }

  const textLower = text.toLowerCase();
  const matches: string[] = [];

  for (const keyword of keywords) {
    if (textLower.includes(keyword.toLowerCase())) {
      matches.push(keyword);
    }
  }

  return matches;
}

/**
 * Check if text starts with any of the specified prefixes (case-insensitive)
 *
 * @param text Text to check
 * @param prefixes Array of prefixes to check for
 * @returns First matching prefix (in original case) or null if no match
 *
 * @example
 * findMatchingPrefix("Invoice #123", ["invoice", "receipt"]) // "invoice"
 * findMatchingPrefix("Hello world", ["payment", "bill"]) // null
 */
export function findMatchingPrefix(text: string, prefixes: string[]): string | null {
  if (!text || !prefixes || prefixes.length === 0) {
    return null;
  }

  const textLower = text.toLowerCase();

  for (const prefix of prefixes) {
    if (textLower.startsWith(prefix.toLowerCase())) {
      return prefix;
    }
  }

  return null;
}

/**
 * Validate email address format (basic validation)
 * For production use, consider using a more comprehensive email validation library
 *
 * @param email Email address to validate
 * @returns True if email appears to be valid format
 */
export function isValidEmailFormat(email: string): boolean {
  // Basic email format validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

/**
 * Normalize email address for comparison
 * Converts to lowercase and trims whitespace
 *
 * @param email Email address to normalize
 * @returns Normalized email address
 */
export function normalizeEmail(email: string): string {
  return email.trim().toLowerCase();
}

