/**
 * Unit Tests for Rule-Based Scoring Stage
 *
 * Tests the sophisticated lexical pattern matching, bounded aggregation, and scoring logic
 * per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 *
 * Constitutional Compliance:
 * - Law 0: Preserves sophisticated classification engine architecture
 * - Law 1: Comprehensive edge case testing prevents functional harm
 * - Law 2: Tests match implementation requirements exactly
 * - Law 3: Clear, maintainable test structure with explainability validation
 */

import {
  executeRuleScoring,
  RuleScoringStageConfig,
  RuleScoringStageConfigSchema,
} from '../../src/stages/rule-scoring';
import {
  EmailMessage,
  TopLevelCategory,
  ProcessingConfig,
  ProcessingSettings,
  MultiLabelPolicy,
  DomainOverrides,
  DomainResolution,
  AttributeSystem,
  AttributeRelevanceMatrix,
  AIPromptSystem,
  JSONSchema,
} from '../../src/types';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

// Helper function to set up test session and result
function setupTest() {
  const settings: ProcessingSettings = {
    initialization: {
      apply_hard_assertions: true,
      seed_category_scores: true,
    },
    rule_scoring: {
      use_lexical_patterns: true,
      apply_subtype_rules: true,
      bounded_aggregation: true,
    },
    attribute_processing: {
      detect_self_sent: true,
      resolve_domains: true,
      derive_context_flags: true,
    },
    attribute_influence: {
      apply_bonuses: true,
      apply_penalties: true,
      enforce_caps: true,
    },
    multi_label_selection: {
      max_labels: 3,
      min_secondary_confidence: 0.5,
      allowed_combinations: [],
    },
    ai_routing: {
      high_confidence_threshold: 0.8,
      ai_required_threshold: 0.3,
      skip_ai_conditions: [],
    },
  };

  const multiLabelPolicy: MultiLabelPolicy = {
    max_top_level_labels: 3,
    min_confidence_for_additional: 0.5,
    min_delta_primary_secondary: 0.2,
    allow_financial_actionable_copresence: true,
  };

  const domainOverrides: DomainOverrides = {};

  const domainResolution: DomainResolution = {
    mode: 'runtime_resolved',
    source: 'config/domain-sources.json',
    notes: 'Test config',
  };

  const attributes: AttributeSystem = {
    schema: {},
    detectors: [],
    derived: {},
    attribute_bonus_map: {},
  };

  const attributeRelevance: AttributeRelevanceMatrix = {
    _roles_legend: {
      CORE: 'Core attribute',
      PRIMARY_BOOST: 'Primary boost',
      SECONDARY_BOOST: 'Secondary boost',
      DISAMBIGUATOR: 'Disambiguator',
